/* ── Tombstone helpers ────────────────────────────────────────────────────── */

/**
 * Resolve the current world position of a tombstone.
 * If it was spawned on a ship, transform local coords via the ship's
 * current position and rotation; otherwise return the static spawn coords.
 */
static void tombstone_world_pos(const Tombstone* t, float* wx, float* wy) {
    if (t->ship_id != 0) {
        const SimpleShip* ship = find_ship(t->ship_id);
        if (ship && ship->active) {
            ship_local_to_world(ship, t->local_x, t->local_y, wx, wy);
            return;
        }
    }
    *wx = t->x;
    *wy = t->y;
}

/**
 * Called when a ship is about to be despawned.
 * Converts every tombstone attached to that ship from ship-local coordinates
 * to world-space and clears the ship attachment so the tombstones persist in
 * the world after the ship is gone.
 */
void detach_tombstones_from_ship(uint16_t ship_id) {
    if (!ship_id) return;
    SimpleShip* ship = find_ship(ship_id);
    for (int _ti = 0; _ti < (int)MAX_TOMBSTONES; _ti++) {
        Tombstone* t = &tombstones[_ti];
        if (!t->active || t->ship_id != ship_id) continue;
        /* Convert local position to world coords using the ship's final transform,
         * then detach. Only orphan the tombstone if the conversion succeeded —
         * if find_ship returned NULL the coordinates were never updated, so leaving
         * the tombstone attached is safer than orphaning it with stale position data. */
        if (ship) {
            ship_local_to_world(ship, t->local_x, t->local_y, &t->x, &t->y);
            t->ship_id = 0;
            t->local_x = 0.0f;
            t->local_y = 0.0f;
        }
    }
}

/* ── Dropped-item helpers ─────────────────────────────────────────────────── */

static void dropped_item_world_pos(const DroppedItem* di, float* wx, float* wy) {
    if (di->ship_id != 0) {
        const SimpleShip* ship = find_ship(di->ship_id);
        if (ship && ship->active) {
            ship_local_to_world(ship, di->local_x, di->local_y, wx, wy);
            return;
        }
    }
    *wx = di->x;
    *wy = di->y;
}

static void dropped_item_set_world_pos(DroppedItem* di, float wx, float wy) {
    if (di->ship_id != 0) {
        const SimpleShip* ship = find_ship(di->ship_id);
        if (ship && ship->active) {
            ship_world_to_local(ship, wx, wy, &di->local_x, &di->local_y);
            ship_local_to_world(ship, di->local_x, di->local_y, &di->x, &di->y);
            return;
        }
        di->ship_id = 0;
        di->local_x = di->local_y = 0.0f;
        di->deck_level = 0;
    }
    di->x = wx;
    di->y = wy;
}

/** Place a dropped item at the player's feet (on-deck if aboard a ship). */
static void place_dropped_item_at_player(DroppedItem* di, WebSocketPlayer* player) {
    const float THROW_DIST = 40.0f;
    if (player->parent_ship_id != 0) {
        const SimpleShip* ship = find_ship(player->parent_ship_id);
        if (ship && ship->active) {
            di->ship_id = player->parent_ship_id;
            di->deck_level = player->deck_level;
            /* Forward offset in ship-local space — stays on deck instead of world throw. */
            float rel_rot = player->rotation - ship->rotation;
            di->local_x = player->local_x + cosf(rel_rot) * THROW_DIST;
            di->local_y = player->local_y + sinf(rel_rot) * THROW_DIST;
            ship_local_to_world(ship, di->local_x, di->local_y, &di->x, &di->y);
            return;
        }
    }
    di->ship_id = 0;
    di->local_x = di->local_y = 0.0f;
    di->deck_level = 0;
    di->x = player->x + cosf(player->rotation) * THROW_DIST;
    di->y = player->y + sinf(player->rotation) * THROW_DIST;
}

void detach_dropped_items_from_ship(uint16_t ship_id) {
    if (!ship_id) return;
    SimpleShip* ship = find_ship(ship_id);
    for (int _di = 0; _di < (int)MAX_DROPPED_ITEMS; _di++) {
        DroppedItem* di = &dropped_items[_di];
        if (!di->active || di->ship_id != ship_id) continue;
        if (ship) {
            ship_local_to_world(ship, di->local_x, di->local_y, &di->x, &di->y);
            di->ship_id = 0;
            di->local_x = 0.0f;
            di->local_y = 0.0f;
            di->deck_level = 0;
        }
    }
}

static SnapShipLut g_blob_worker_lut;
static SnapShipLut g_blob_sync_lut;

static void build_shared_blobs_from_snapshot(const SharedBlobSnapshot* snap, SharedBlobOutput* out,
                                             SnapShipLut* lut) {
    out->tick = snap->tick;   /* keep positions and tick label paired through async handoff */
    snap_ship_lut_fill(lut, snap);
    build_ships_blob_from_snapshot(snap, out, lut);

    out->tmb_json[0] = '[';
    int _to = 1;
    bool _tf = true;
    for (int _ti = 0; _ti < (int)MAX_TOMBSTONES; _ti++) {
        if (!snap->tombstones[_ti].active) continue;
        uint32_t _age = snap->current_time - snap->tombstones[_ti].spawn_time_ms;
        uint32_t _rem = (_age < TOMBSTONE_TTL_MS) ? (TOMBSTONE_TTL_MS - _age) : 0u;
        float _tx = snap->tombstones[_ti].x;
        float _ty = snap->tombstones[_ti].y;
        if (snap->tombstones[_ti].ship_id != 0) {
            const SimpleShip* _ship = snap_ship_lut_get(lut, snap->tombstones[_ti].ship_id);
            if (_ship) {
                float _c = cosf(_ship->rotation), _s = sinf(_ship->rotation);
                _tx = _ship->x + (snap->tombstones[_ti].local_x * _c - snap->tombstones[_ti].local_y * _s);
                _ty = _ship->y + (snap->tombstones[_ti].local_x * _s + snap->tombstones[_ti].local_y * _c);
            }
        }
        if (!_tf && _to < (int)sizeof(out->tmb_json) - 2) out->tmb_json[_to++] = ',';
        _to += snprintf(out->tmb_json + _to, sizeof(out->tmb_json) - _to,
            "{\"id\":%u,\"x\":%.1f,\"y\":%.1f,\"ownerName\":\"%s\",\"remainingMs\":%u}",
            snap->tombstones[_ti].id, _tx, _ty, snap->tombstones[_ti].owner_name, _rem);
        _tf = false;
    }
    if (_to < (int)sizeof(out->tmb_json) - 1) out->tmb_json[_to++] = ']';
    out->tmb_json[_to] = '\0';
    out->tmb_len = _to;

    out->ditem_json[0] = '[';
    int _do = 1;
    bool _df = true;
    bool _ditem_truncated = false;
    for (int _di = 0; _di < (int)MAX_DROPPED_ITEMS; _di++) {
        if (!snap->dropped_items[_di].active) continue;
        /* Reserve headroom for one worst-case schematic entry + closing ']'. */
        if (_do >= (int)sizeof(out->ditem_json) - 256) {
            _ditem_truncated = true;
            break;
        }
        if (!_df && _do < (int)sizeof(out->ditem_json) - 2) out->ditem_json[_do++] = ',';
        uint32_t _dage = snap->current_time - snap->dropped_items[_di].spawn_time_ms;
        uint32_t _drem = (_dage < DROPPED_ITEM_TTL_MS) ? (DROPPED_ITEM_TTL_MS - _dage) : 0u;
        float _dx = snap->dropped_items[_di].x;
        float _dy = snap->dropped_items[_di].y;
        uint16_t _dship_id = snap->dropped_items[_di].ship_id;
        if (_dship_id != 0) {
            const SimpleShip* _dship = snap_ship_lut_get(lut, _dship_id);
            if (_dship) {
                float _dc = cosf(_dship->rotation), _ds = sinf(_dship->rotation);
                _dx = _dship->x + (snap->dropped_items[_di].local_x * _dc - snap->dropped_items[_di].local_y * _ds);
                _dy = _dship->y + (snap->dropped_items[_di].local_x * _ds + snap->dropped_items[_di].local_y * _dc);
            }
        }
        int _dn = 0;
        if (snap->dropped_items[_di].is_schematic) {
            const QualityPayload* _dq = &snap->dropped_items[_di].quality;
            float _dqual = quality_from_q8(_dq->quality_q8);
            if (_dship_id != 0) {
                _dn = snprintf(out->ditem_json + _do, sizeof(out->ditem_json) - (size_t)_do,
                    "{\"id\":%u,\"itemKind\":%u,\"quantity\":%u,\"x\":%.1f,\"y\":%.1f,"
                    "\"remainingMs\":%u,\"isSchematic\":true,\"crafts\":%u,"
                    "\"quality\":%.2f,\"tier\":%d,\"stats\":[%u,%u,%u,%u,%u],"
                    "\"shipId\":%u,\"deckLevel\":%u}",
                    snap->dropped_items[_di].id, (unsigned)snap->dropped_items[_di].item_kind,
                    (unsigned)snap->dropped_items[_di].quantity,
                    _dx, _dy, _drem,
                    (unsigned)snap->dropped_items[_di].crafts_remaining,
                    _dqual, quality_tier(_dqual),
                    (unsigned)_dq->stat_mult_q8[0], (unsigned)_dq->stat_mult_q8[1],
                    (unsigned)_dq->stat_mult_q8[2], (unsigned)_dq->stat_mult_q8[3],
                    (unsigned)_dq->stat_mult_q8[4],
                    (unsigned)_dship_id, (unsigned)snap->dropped_items[_di].deck_level);
            } else {
                _dn = snprintf(out->ditem_json + _do, sizeof(out->ditem_json) - (size_t)_do,
                    "{\"id\":%u,\"itemKind\":%u,\"quantity\":%u,\"x\":%.1f,\"y\":%.1f,"
                    "\"remainingMs\":%u,\"isSchematic\":true,\"crafts\":%u,"
                    "\"quality\":%.2f,\"tier\":%d,\"stats\":[%u,%u,%u,%u,%u]}",
                    snap->dropped_items[_di].id, (unsigned)snap->dropped_items[_di].item_kind,
                    (unsigned)snap->dropped_items[_di].quantity,
                    _dx, _dy, _drem,
                    (unsigned)snap->dropped_items[_di].crafts_remaining,
                    _dqual, quality_tier(_dqual),
                    (unsigned)_dq->stat_mult_q8[0], (unsigned)_dq->stat_mult_q8[1],
                    (unsigned)_dq->stat_mult_q8[2], (unsigned)_dq->stat_mult_q8[3],
                    (unsigned)_dq->stat_mult_q8[4]);
            }
        } else {
            if (_dship_id != 0) {
                _dn = snprintf(out->ditem_json + _do, sizeof(out->ditem_json) - (size_t)_do,
                    "{\"id\":%u,\"itemKind\":%u,\"quantity\":%u,\"x\":%.1f,\"y\":%.1f,"
                    "\"remainingMs\":%u,\"shipId\":%u,\"deckLevel\":%u}",
                    snap->dropped_items[_di].id, (unsigned)snap->dropped_items[_di].item_kind,
                    (unsigned)snap->dropped_items[_di].quantity,
                    _dx, _dy, _drem,
                    (unsigned)_dship_id, (unsigned)snap->dropped_items[_di].deck_level);
            } else {
                _dn = snprintf(out->ditem_json + _do, sizeof(out->ditem_json) - (size_t)_do,
                    "{\"id\":%u,\"itemKind\":%u,\"quantity\":%u,\"x\":%.1f,\"y\":%.1f,\"remainingMs\":%u}",
                    snap->dropped_items[_di].id, (unsigned)snap->dropped_items[_di].item_kind,
                    (unsigned)snap->dropped_items[_di].quantity,
                    _dx, _dy, _drem);
            }
        }
        if (_dn < 0 || (size_t)_dn >= sizeof(out->ditem_json) - (size_t)_do) {
            _do = (_do < (int)sizeof(out->ditem_json) - 2)
                ? _do : (int)sizeof(out->ditem_json) - 2;
            _ditem_truncated = true;
            break;
        }
        _do += _dn;
        _df = false;
    }
    if (_ditem_truncated) {
        log_warn("📦  droppedItems JSON truncated at %d bytes (cap %zu)",
                 _do, sizeof(out->ditem_json));
    }
    if (_do < (int)sizeof(out->ditem_json) - 1) out->ditem_json[_do++] = ']';
    out->ditem_json[_do] = '\0';
    out->ditem_len = _do;

    out->co_json[0] = '[';
    int _co = 1;
    bool _cf = true;
    int _dcc = snap->dynamic_company_count;
    if (_dcc < 0) _dcc = 0;
    if (_dcc > MAX_DYNAMIC_COMPANIES) _dcc = MAX_DYNAMIC_COMPANIES;
    for (int _ci2 = 0; _ci2 < _dcc; _ci2++) {
        if (!snap->dynamic_companies[_ci2].active) continue;
        if (!_cf && _co < (int)sizeof(out->co_json) - 2) out->co_json[_co++] = ',';
        _co += snprintf(out->co_json + _co, sizeof(out->co_json) - _co,
            "{\"id\":%u,\"name\":\"%s\",\"founderId\":%u}",
            snap->dynamic_companies[_ci2].id, snap->dynamic_companies[_ci2].name,
            snap->dynamic_companies[_ci2].founder_id);
        _cf = false;
    }
    if (_co < (int)sizeof(out->co_json) - 1) out->co_json[_co++] = ']';
    out->co_json[_co] = '\0';
    out->co_len = _co;

    /* players_json is not used in the send path — the per-client AOI assembly
     * reads player_entry[] directly (same pattern as npcs_json, skipped above).
     * Skip building the combined blob to avoid a redundant 65 KB buffer write. */
    out->players_json[0] = '\0';
    out->players_len = 0;
    int active_count = 0;
    memset(out->player_entry_active, 0, sizeof(out->player_entry_active));
    for (int p = 0; p < WS_MAX_CLIENTS; p++) {
        if (!snap->players[p].active) continue;

        char inv_buf[1024];
        int inv_off = 0;
        inv_off += snprintf(inv_buf + inv_off, sizeof(inv_buf) - inv_off,
                            ",\"inventory\":{\"slots\":[");
        for (int s = 0; s < INVENTORY_SLOTS; s++) {
            if (s > 0 && inv_off < (int)sizeof(inv_buf) - 1)
                inv_buf[inv_off++] = ',';
            inv_off += snprintf(inv_buf + inv_off, sizeof(inv_buf) - inv_off,
                                "[%d,%d]",
                                (int)snap->players[p].inventory.slots[s].item,
                                (int)snap->players[p].inventory.slots[s].quantity);
        }
        inv_off += snprintf(inv_buf + inv_off, sizeof(inv_buf) - inv_off,
                            "],\"equip\":{\"helm\":%d,\"torso\":%d,\"legs\":%d,"
                            "\"feet\":%d,\"hands\":%d,\"shield\":%d},"
                            "\"activeSlot\":%d,"
                            "\"res_wood\":%u,\"res_fiber\":%u,\"res_metal\":%u,\"res_stone\":%u}",
                            (int)snap->players[p].inventory.equipment.helm,
                            (int)snap->players[p].inventory.equipment.torso,
                            (int)snap->players[p].inventory.equipment.legs,
                            (int)snap->players[p].inventory.equipment.feet,
                            (int)snap->players[p].inventory.equipment.hands,
                            (int)snap->players[p].inventory.equipment.shield,
                            (int)snap->players[p].inventory.active_slot,
                            (unsigned)snap->players[p].res_wood,
                            (unsigned)snap->players[p].res_fiber,
                            (unsigned)snap->players[p].res_metal,
                            (unsigned)snap->players[p].res_stone);

        /* Effective movement speed multiplier — accounts for carry weight + grapple load. */
        float _snap_inv_kg    = blob_player_inventory_weight(&snap->players[p]);
        if (players[p].active && players[p].player_id == snap->players[p].player_id)
            _snap_inv_kg = player_grapple_carry_kg(p, &players[p]);
        float _snap_carry_cap = 300.0f * (1.0f + (float)snap->players[p].stat_weight * 0.1f);
        float _snap_carry_r   = (_snap_carry_cap > 0.0f) ? (_snap_inv_kg / _snap_carry_cap) : 0.0f;
        float _snap_spd_mult  = _snap_carry_r >= 1.0f ? 0.3f : fmaxf(0.3f, 1.0f - _snap_carry_r * 0.5f);
        bool  _snap_can_sprint = (_snap_carry_r < 0.85f);

        char player_entry[3200];
        int _pelen = snprintf(player_entry, sizeof(player_entry),
                "{\"id\":%u,\"name\":\"%s\",\"world_x\":%.1f,\"world_y\":%.1f,\"rotation\":%.3f,"
                "\"velocity_x\":%.2f,\"velocity_y\":%.2f,\"is_moving\":%s,"
                "\"movement_direction_x\":%.2f,\"movement_direction_y\":%.2f,"
                "\"parent_ship\":%u,\"local_x\":%.1f,\"local_y\":%.1f,\"deck_level\":%u,\"state\":\"%s\","
                "\"is_mounted\":%s,\"mounted_module_id\":%u,\"controlling_ship\":%u,"
                "\"company\":%u,\"health\":%u,\"max_health\":%u,"
                "\"stamina\":%u,\"max_stamina\":%u,\"oxygen\":%u,\"max_oxygen\":%u,"
                "\"on_island\":%u,\"on_dock\":%u,"
                "\"player_level\":%u,\"player_xp\":%u,"
                "\"stat_health\":%u,\"stat_damage\":%u,\"stat_stamina\":%u,\"stat_weight\":%u,"
                "\"stat_points\":%u,"
                "\"speed_mult\":%.4f,\"can_sprint\":%s,"
                "\"bucket_fill\":%u"
                "%s}",
                snap->players[p].player_id, snap->players[p].name[0] ? snap->players[p].name : "Player",
                snap->players[p].x, snap->players[p].y, snap->players[p].rotation,
                snap->players[p].velocity_x, snap->players[p].velocity_y,
                snap->players[p].is_moving ? "true" : "false",
                snap->players[p].movement_direction_x, snap->players[p].movement_direction_y,
                snap->players[p].parent_ship_id, snap->players[p].local_x, snap->players[p].local_y,
                (unsigned)snap->players[p].deck_level,
                get_state_string(snap->players[p].movement_state),
                snap->players[p].is_mounted ? "true" : "false",
                snap->players[p].mounted_module_id,
                snap->players[p].controlling_ship_id,
                snap->players[p].company_id,
                snap->players[p].health, snap->players[p].max_health,
                snap->players[p].stamina, snap->players[p].max_stamina,
                snap->players[p].oxygen,  snap->players[p].max_oxygen,
                snap->players[p].on_island_id, snap->players[p].on_dock_id,
                (unsigned)snap->players[p].player_level,
                (unsigned)snap->players[p].player_xp,
                (unsigned)snap->players[p].stat_health,
                (unsigned)snap->players[p].stat_damage,
                (unsigned)snap->players[p].stat_stamina,
                (unsigned)snap->players[p].stat_weight,
                (unsigned)((snap->players[p].player_level > 1)
                    ? (snap->players[p].player_level - 1)
                      - (snap->players[p].stat_health + snap->players[p].stat_damage
                         + snap->players[p].stat_stamina + snap->players[p].stat_weight)
                    : 0),
                _snap_spd_mult, _snap_can_sprint ? "true" : "false",
                (unsigned)snap->players[p].bucket_fill,
                inv_buf);
        if (_pelen < 0) _pelen = 0;
        if (_pelen >= (int)sizeof(player_entry)) _pelen = (int)sizeof(player_entry) - 1;
        /* Append active grapple state so the client can render the rope.
         * Only included when the hook is in flight or attached. */
        {
            const GrappleHook* _gh = &grapple_hooks[p];
            if (_gh->active && _gh->state != GRAPPLE_IDLE) {
                /* Inject before the closing '}' */
                if (_pelen > 1 && player_entry[_pelen - 1] == '}') {
                    char _gbuf[128];
                    int _gn = snprintf(_gbuf, sizeof(_gbuf),
                        ",\"grapple_state\":%d,\"grapple_x\":%.1f,\"grapple_y\":%.1f,\"grapple_rope\":%.1f,\"grapple_target\":%d}",
                        (int)_gh->state, _gh->hook_x, _gh->hook_y, _gh->rope_length,
                        (_gh->state == GRAPPLE_ATTACHED) ? _gh->target_type : GRAPPLE_TARGET_NONE);
                    if (_gn > 0) {
                        int _base = _pelen - 1;
                        if (_base + _gn < (int)sizeof(player_entry)) {
                            memcpy(player_entry + _base, _gbuf, (size_t)_gn);
                            _pelen = _base + _gn;
                            player_entry[_pelen] = '\0';
                        }
                    }
                }
            }
        }
        /* Capture per-entry for AOI-filtered per-client assembly. */
        {
            if (_pelen > (int)sizeof(out->player_entry[p]) - 1) _pelen = (int)sizeof(out->player_entry[p]) - 1;
            memcpy(out->player_entry[p], player_entry, (size_t)_pelen);
            out->player_entry[p][_pelen] = '\0';
            out->player_entry_len[p] = _pelen;
            float _pwx = snap->players[p].x, _pwy = snap->players[p].y;
            if (snap->players[p].parent_ship_id != 0) {
                float _spx, _spy;
                if (snap_ship_lut_aoi_pos(lut, out, snap->players[p].parent_ship_id, &_spx, &_spy)) {
                    _pwx = _spx;
                    _pwy = _spy;
                }
            }
            out->player_world_x[p] = _pwx;
            out->player_world_y[p] = _pwy;
            out->player_entry_active[p] = true;
        }
        active_count++;
    }
    out->active_player_count = active_count;

    int projectiles_offset = 0;
    out->projectiles_json[projectiles_offset++] = '[';
    bool first_projectile = true;
    uint16_t _pc = snap->projectile_count;
    if (_pc > MAX_PROJECTILES) _pc = MAX_PROJECTILES;
    for (uint16_t p = 0; p < _pc; p++) {
        const struct Projectile* proj = &snap->projectiles[p];
        if (!first_projectile) {
            if (projectiles_offset < (int)sizeof(out->projectiles_json) - 1)
                out->projectiles_json[projectiles_offset++] = ',';
        }
        float proj_x = SERVER_TO_CLIENT(Q16_TO_FLOAT(proj->position.x));
        float proj_y = SERVER_TO_CLIENT(Q16_TO_FLOAT(proj->position.y));
        float proj_vx = SERVER_TO_CLIENT(Q16_TO_FLOAT(proj->velocity.x));
        float proj_vy = SERVER_TO_CLIENT(Q16_TO_FLOAT(proj->velocity.y));
        projectiles_offset += snprintf(out->projectiles_json + projectiles_offset,
                                       sizeof(out->projectiles_json) - projectiles_offset,
                                       "{\"id\":%u,\"x\":%.1f,\"y\":%.1f,\"vx\":%.1f,\"vy\":%.1f,\"type\":%u,\"owner\":%u}",
                                       proj->id, proj_x, proj_y, proj_vx, proj_vy, proj->type, proj->owner_id);
        first_projectile = false;
    }
    if (projectiles_offset < (int)sizeof(out->projectiles_json) - 1)
        out->projectiles_json[projectiles_offset++] = ']';
    out->projectiles_json[projectiles_offset] = '\0';
    out->projectiles_len = projectiles_offset;

    /* NPC entries: serialise directly into per-entry cache; no combined blob.
     * The old approach wrote all NPCs into npcs_json[32768], but with up to
     * MAX_WORLD_NPCS (512) active NPCs at ~500 bytes each (~256 KB needed)
     * the 32 KB buffer overflowed.  snprintf's signed/unsigned subtraction
     * (sizeof - int offset) wraps to a huge size_t once offset > sizeof,
     * allowing writes past the buffer end that corrupt adjacent struct fields
     * (tmb_len, ditem_len, players_len …) and produce non-UTF-8 WebSocket
     * frames.  The per-client send path already reads npc_entry[] directly;
     * npcs_json is not used in any send path, so we skip building it. */
    memset(out->npc_entry_active, 0, sizeof(out->npc_entry_active));
    int _wnc = snap->world_npc_count;
    if (_wnc < 0) _wnc = 0;
    if (_wnc > MAX_WORLD_NPCS) _wnc = MAX_WORLD_NPCS;
    out->npc_entry_count = _wnc;
    for (int n = 0; n < _wnc; n++) {
        const WorldNpc* npc = &snap->world_npcs[n];
        if (!npc->active) continue;

        /* Dirty-flag: skip snprintf if every serialized field is unchanged. */
        __typeof__(out->npc_key[n]) *_k = &out->npc_key[n];
        bool _dirty = (_k->id             != npc->id             ||
                       _k->x              != npc->x              ||
                       _k->y              != npc->y              ||
                       _k->rotation       != npc->rotation       ||
                       _k->ship_id        != npc->ship_id        ||
                       _k->local_x        != npc->local_x        ||
                       _k->local_y        != npc->local_y        ||
                       _k->owner_player_id!= npc->owner_player_id||
                       _k->assigned_weapon_id != npc->assigned_weapon_id ||
                       _k->xp             != npc->xp             ||
                       _k->health         != npc->health         ||
                       _k->max_health     != npc->max_health     ||
                       _k->state          != (uint8_t)npc->state ||
                       _k->role           != (uint8_t)npc->role  ||
                       _k->company_id     != npc->company_id     ||
                       _k->deck_level     != (uint8_t)npc->deck_level ||
                       _k->npc_level      != npc->npc_level      ||
                       _k->stat_health    != npc->stat_health    ||
                       _k->stat_damage    != npc->stat_damage    ||
                       _k->stat_stamina   != npc->stat_stamina   ||
                       _k->stat_weight    != npc->stat_weight    ||
                       _k->task_locked    != (uint8_t)npc->task_locked ||
                       strncmp(_k->name, npc->name, sizeof(_k->name)) != 0 ||
                       out->npc_entry_len[n] == 0);

        if (_dirty) {
            int _nlen = snprintf(out->npc_entry[n], sizeof(out->npc_entry[n]),
                "{\"id\":%u,\"name\":\"%s\",\"type\":0,"
                "\"x\":%.1f,\"y\":%.1f,\"rotation\":%.3f,"
                "\"ship_id\":%u,\"local_x\":%.1f,\"local_y\":%.1f,"
                "\"interact_radius\":%.1f,\"state\":%u,\"role\":%u,\"company\":%u,"
                "\"owner_id\":%u,"
                "\"assigned_weapon_id\":%u,"
                "\"deck_level\":%u,"
                "\"npc_level\":%u,\"health\":%u,\"max_health\":%u,\"xp\":%u,"
                "\"stat_health\":%u,\"stat_damage\":%u,\"stat_stamina\":%u,\"stat_weight\":%u,"
                "\"stat_points\":%u,\"locked\":%d}",
                npc->id, npc->name,
                npc->x, npc->y, npc->rotation,
                npc->ship_id, npc->local_x, npc->local_y,
                npc->interact_radius, (unsigned)npc->state, (unsigned)npc->role, (unsigned)npc->company_id,
                npc->owner_player_id,
                npc->assigned_weapon_id,
                (unsigned)npc->deck_level,
                (unsigned)npc->npc_level, (unsigned)npc->health, (unsigned)npc->max_health, npc->xp,
                (unsigned)npc->stat_health, (unsigned)npc->stat_damage, (unsigned)npc->stat_stamina, (unsigned)npc->stat_weight,
                (unsigned)((npc->npc_level > 0u ? (uint8_t)(npc->npc_level - 1u) : 0u) -
                    (npc->stat_health + npc->stat_damage + npc->stat_stamina + npc->stat_weight)),
                (int)npc->task_locked);
            if (_nlen < 0) _nlen = 0;
            if (_nlen >= (int)sizeof(out->npc_entry[n]))
                _nlen = (int)sizeof(out->npc_entry[n]) - 1;
            out->npc_entry[n][_nlen] = '\0';
            out->npc_entry_len[n] = _nlen;

            /* Update cached key */
            _k->id              = npc->id;
            _k->x               = npc->x;
            _k->y               = npc->y;
            _k->rotation        = npc->rotation;
            _k->ship_id         = npc->ship_id;
            _k->local_x         = npc->local_x;
            _k->local_y         = npc->local_y;
            _k->owner_player_id = npc->owner_player_id;
            _k->assigned_weapon_id = npc->assigned_weapon_id;
            _k->xp              = npc->xp;
            _k->health          = npc->health;
            _k->max_health      = npc->max_health;
            _k->state           = (uint8_t)npc->state;
            _k->role            = (uint8_t)npc->role;
            _k->company_id      = npc->company_id;
            _k->deck_level      = (uint8_t)npc->deck_level;
            _k->npc_level       = npc->npc_level;
            _k->stat_health     = npc->stat_health;
            _k->stat_damage     = npc->stat_damage;
            _k->stat_stamina    = npc->stat_stamina;
            _k->stat_weight     = npc->stat_weight;
            _k->task_locked     = (uint8_t)npc->task_locked;
            strncpy(_k->name, npc->name, sizeof(_k->name) - 1);
            _k->name[sizeof(_k->name) - 1] = '\0';
        }

        float _nwx = npc->x, _nwy = npc->y;
        if (npc->ship_id != 0) {
            float _nspx, _nspy;
            if (snap_ship_lut_aoi_pos(lut, out, npc->ship_id, &_nspx, &_nspy)) {
                _nwx = _nspx;
                _nwy = _nspy;
            }
        }
        out->npc_world_x[n] = _nwx;
        out->npc_world_y[n] = _nwy;
        out->npc_entry_active[n] = true;
    }
    /* npcs_json is unused in the send path; mark empty so stale data is never read. */
    out->npcs_json[0] = '\0';
    out->npcs_len = 0;
}

static void build_ships_blob_from_snapshot(const SharedBlobSnapshot* snap, SharedBlobOutput* out,
                                           SnapShipLut* lut) {
    int ships_offset = 0;
    out->ships_json[ships_offset++] = '[';
    bool first_ship = true;
    out->aoi_ship_count = 0;

    if (snap->sim_ship_count > 0) {
        uint16_t _ssc = snap->sim_ship_count;
        if (_ssc > MAX_SHIPS) _ssc = MAX_SHIPS;
        for (uint16_t s = 0; s < _ssc; s++) {
            const struct Ship* ship = &snap->sim_ships[s];
            /* Reserve 32 bytes so the closing ']' always fits */
            if (ships_offset >= (int)sizeof(out->ships_json) - 32) {
                log_warn("⚠️  ships_json near capacity (%d/%zu) — skipping remaining ships",
                         ships_offset, sizeof(out->ships_json));
                break;
            }
            if (!first_ship) {
                if (ships_offset < (int)sizeof(out->ships_json) - 1)
                    out->ships_json[ships_offset++] = ',';
            }

            float pos_x = SERVER_TO_CLIENT(Q16_TO_FLOAT(ship->position.x));
            float pos_y = SERVER_TO_CLIENT(Q16_TO_FLOAT(ship->position.y));
            float rotation = Q16_TO_FLOAT(ship->rotation);
            float vel_x = SERVER_TO_CLIENT(Q16_TO_FLOAT(ship->velocity.x));
            float vel_y = SERVER_TO_CLIENT(Q16_TO_FLOAT(ship->velocity.y));
            float ang_vel = Q16_TO_FLOAT(ship->angular_velocity);
            float rudder_radians = ship->rudder_angle * (3.14159f / 180.0f);

            const SimpleShip* simple_ship = ship->id > 0 ? snap_ship_lut_get(lut, ship->id) : NULL;

            char ship_entry[16384];
            float hull_health_pct = (simple_ship && simple_ship->ship_type == SHIP_TYPE_GHOST)
                ? (float)ship->hull_health
                : Q16_TO_FLOAT(ship->hull_health);
            int offset = snprintf(ship_entry, sizeof(ship_entry),
                    "{\"id\":%u,\"seq\":%u,\"name\":\"%s\",\"x\":%.2f,\"y\":%.2f,\"rotation\":%.4f,"
                    "\"velocity_x\":%.3f,\"velocity_y\":%.3f,\"angular_velocity\":%.4f,"
                    "\"rudder_angle\":%.4f,"
                    "\"hullHealth\":%.2f,\"company\":%u,\"shipType\":%u,"
                    "\"npcLevel\":%u,"
                    /* Live mass (crew + cargo + modules, via recalc_ship_mass) — the client
                     * ship predictor needs it for the wind-speed mass ratio; without it the
                     * client assumes the template mass and mispredicts top speed whenever
                     * anyone/anything is aboard. */
                    "\"mass\":%.0f,"
                    "\"ammo\":%u,\"infiniteAmmo\":%s,\"modules\":[",
                    ship->id, simple_ship ? simple_ship->ship_seq : (uint8_t)(ship->id & 0xFF),
                    simple_ship ? simple_ship->ship_name : "",
                    pos_x, pos_y, rotation, vel_x, vel_y, ang_vel,
                    rudder_radians,
                    hull_health_pct,
                    simple_ship ? simple_ship->company_id : COMPANY_NEUTRAL,
                    simple_ship ? simple_ship->ship_type  : SHIP_TYPE_BRIGANTINE,
                    (unsigned)(simple_ship ? simple_ship->npc_level : 0),
                    simple_ship ? simple_ship->mass : BRIGANTINE_MASS,
                    simple_ship ? simple_ship->cannon_ammo : 0,
                    (simple_ship && simple_ship->infinite_ammo) ? "true" : "false");

            for (uint8_t m = 0; m < ship->module_count && offset < (int)sizeof(ship_entry) - 200; m++) {
                const ShipModule* module = &ship->modules[m];
                if (module->type_id == MODULE_TYPE_PLANK) {
                    offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                        "%s{\"id\":%u,\"typeId\":%u,\"health\":%d,\"targetHealth\":%d,\"maxHealth\":%d,\"qt\":%d,\"qd\":%u}",
                        m > 0 ? "," : "", module->id, module->type_id,
                        (int)module->health, (int)module->target_health, (int)module->max_health,
                        module_quality_tier(module),
                        (unsigned)module->quality.stat_mult_q8[STAT_DURABILITY]);
                } else if (module->type_id == MODULE_TYPE_DECK) {
                    offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                        "%s{\"id\":%u,\"typeId\":%u,\"health\":%d,\"maxHealth\":%d,\"targetHealth\":%d,\"stateBits\":%u,\"deck_id\":%u,\"qt\":%d,\"qd\":%u}",
                        m > 0 ? "," : "", module->id, module->type_id,
                        (int)module->health, (int)module->max_health, (int)module->target_health,
                        (unsigned)module->state_bits, (unsigned)module->deck_id,
                        module_quality_tier(module),
                        (unsigned)module->quality.stat_mult_q8[STAT_DURABILITY]);
                } else {
                    float module_x = SERVER_TO_CLIENT(Q16_TO_FLOAT(module->local_pos.x));
                    float module_y = SERVER_TO_CLIENT(Q16_TO_FLOAT(module->local_pos.y));
                    float module_rot = Q16_TO_FLOAT(module->local_rot);
                    if (module->type_id == MODULE_TYPE_MAST) {
                        float sail_angle = Q16_TO_FLOAT(module->data.mast.angle);
                        float wind_eff   = Q16_TO_FLOAT(module->data.mast.wind_efficiency);
                        float fh         = Q16_TO_FLOAT(module->data.mast.fiber_health);
                        float fhmax      = Q16_TO_FLOAT(module->data.mast.fiber_max_health);
                        offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                            "%s{\"id\":%u,\"typeId\":%u,\"x\":%.1f,\"y\":%.1f,\"rotation\":%.2f,\"openness\":%u,\"sailAngle\":%.3f,\"windEfficiency\":%.3f,\"fiberHealth\":%.0f,\"fiberMaxHealth\":%.0f,\"fiberFireIntensity\":%u,\"health\":%d,\"targetHealth\":%d,\"maxHealth\":%d,\"deck_id\":%u,\"qt\":%d,\"qse\":%u}",
                            m > 0 ? "," : "", module->id, module->type_id,
                            module_x, module_y, module_rot, module->data.mast.openness, sail_angle, wind_eff,
                            fh, fhmax, (unsigned)module->data.mast.sail_fire_intensity,
                            (int)module->health, (int)module->target_health, (int)module->max_health,
                            (unsigned)module->deck_id, module_quality_tier(module),
                            (unsigned)module->quality.stat_mult_q8[STAT_SAIL_EFFECTIVENESS]);
                    } else if (module->type_id == MODULE_TYPE_CANNON) {
                        float aim_direction = Q16_TO_FLOAT(module->data.cannon.aim_direction);
                        offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                            "%s{\"id\":%u,\"typeId\":%u,\"x\":%.1f,\"y\":%.1f,\"rotation\":%.2f,\"aimDir\":%.3f,\"state\":%u,\"health\":%d,\"targetHealth\":%d,\"maxHealth\":%d,\"deck_id\":%u,\"gunportSnapIdx\":%u,\"qt\":%d,\"qw\":%u}",
                            m > 0 ? "," : "", module->id, module->type_id,
                            module_x, module_y, module_rot, aim_direction,
                            (unsigned)module->state_bits,
                            (int)module->health, (int)module->target_health, (int)module->max_health,
                            (unsigned)module->deck_id,
                            (unsigned)module->data.cannon.gunport_snap_idx, module_quality_tier(module),
                            (unsigned)module->quality.stat_mult_q8[STAT_WEAPON_DAMAGE]);
                    } else if (module->type_id == MODULE_TYPE_SWIVEL) {
                        float aim_dir = Q16_TO_FLOAT(module->data.swivel.aim_direction);
                        offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                            "%s{\"id\":%u,\"typeId\":%u,\"x\":%.1f,\"y\":%.1f,\"rotation\":%.2f,\"aimDir\":%.3f,\"state\":%u,\"health\":%d,\"targetHealth\":%d,\"maxHealth\":%d,\"deck_id\":%u,\"qt\":%d,\"qw\":%u}",
                            m > 0 ? "," : "", module->id, module->type_id,
                            module_x, module_y, module_rot, aim_dir,
                            (unsigned)module->state_bits,
                            (int)module->health, (int)module->target_health, (int)module->max_health,
                            (unsigned)module->deck_id, module_quality_tier(module),
                            (unsigned)module->quality.stat_mult_q8[STAT_WEAPON_DAMAGE]);
                    } else if (module->type_id == MODULE_TYPE_HELM || module->type_id == MODULE_TYPE_STEERING_WHEEL) {
                        float wheel_rot = Q16_TO_FLOAT(module->data.helm.wheel_rotation);
                        offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                            "%s{\"id\":%u,\"typeId\":%u,\"x\":%.1f,\"y\":%.1f,\"rotation\":%.2f,\"wheelRot\":%.3f,\"occupied\":%s,\"state\":%u,\"health\":%d,\"targetHealth\":%d,\"maxHealth\":%d,\"deck_id\":%u}",
                            m > 0 ? "," : "", module->id, module->type_id,
                            module_x, module_y, module_rot, wheel_rot,
                            (module->data.helm.occupied_by != 0) ? "true" : "false",
                            (unsigned)module->state_bits,
                            (int)module->health, (int)module->target_health, (int)module->max_health,
                            (unsigned)module->deck_id);
                    } else if (module->type_id == MODULE_TYPE_GUNPORT) {
                        offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                            "%s{\"id\":%u,\"typeId\":%u,\"x\":%.1f,\"y\":%.1f,\"rotation\":%.2f,\"isOpen\":%s,\"state\":%u,\"deck_id\":%u,\"snapIndex\":%u}",
                            m > 0 ? "," : "", module->id, module->type_id,
                            module_x, module_y, module_rot,
                            module->data.gunport.is_open ? "true" : "false",
                            (unsigned)module->state_bits,
                            (unsigned)module->deck_id,
                            (unsigned)module->data.gunport.snap_idx);
                    } else if (module->type_id == MODULE_TYPE_CHEST) {
                        offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                            "%s{\"id\":%u,\"typeId\":%u,\"x\":%.1f,\"y\":%.1f,\"rotation\":%.2f,\"state\":%u,\"health\":%d,\"maxHealth\":%d,\"deck_id\":%u"
                            ",\"wood\":%u,\"fiber\":%u,\"metal\":%u,\"stone\":%u}",
                            m > 0 ? "," : "", module->id, module->type_id,
                            module_x, module_y, module_rot, (unsigned)module->state_bits,
                            (int)module->health, (int)module->max_health,
                            (unsigned)module->deck_id,
                            (unsigned)module->data.chest.wood,
                            (unsigned)module->data.chest.fiber,
                            (unsigned)module->data.chest.metal,
                            (unsigned)module->data.chest.stone);
                    } else if (module->type_id == MODULE_TYPE_PLANK ||
                               module->type_id == MODULE_TYPE_DECK) {
                        /* Planks and decks send quality tier + durability multiplier so the
                         * client can display blueprint quality in hover tooltips and menus. */
                        offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                            "%s{\"id\":%u,\"typeId\":%u,\"x\":%.1f,\"y\":%.1f,\"rotation\":%.2f,\"state\":%u,\"health\":%d,\"maxHealth\":%d,\"deck_id\":%u,\"qt\":%d,\"qd\":%u}",
                            m > 0 ? "," : "", module->id, module->type_id,
                            module_x, module_y, module_rot, (unsigned)module->state_bits,
                            (int)module->health, (int)module->max_health,
                            (unsigned)module->deck_id,
                            module_quality_tier(module),
                            (unsigned)module->quality.stat_mult_q8[STAT_DURABILITY]);
                    } else {
                        offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                            "%s{\"id\":%u,\"typeId\":%u,\"x\":%.1f,\"y\":%.1f,\"rotation\":%.2f,\"state\":%u,\"health\":%d,\"maxHealth\":%d,\"deck_id\":%u}",
                            m > 0 ? "," : "", module->id, module->type_id,
                            module_x, module_y, module_rot, (unsigned)module->state_bits,
                            (int)module->health, (int)module->max_health,
                            (unsigned)module->deck_id);
                    }
                }
            }

            uint32_t cur_xp = ship->level_stats.xp;
            uint32_t cur_tp = (uint32_t)ship_level_total_points(&ship->level_stats);
            offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                "],\"levelStats\":{"
                "\"weight\":%u,\"resistance\":%u,\"damage\":%u,\"crew\":%u,\"sturdiness\":%u,"
                "\"xp\":%u,\"maxCrew\":%u,"
                "\"shipLevel\":%u,\"totalPoints\":%u,\"totalCap\":%u,"
                "\"nextUpgradeCost\":%u,"
                "\"attrCaps\":{\"weight\":%u,\"resistance\":%u,\"damage\":%u,\"crew\":%u,\"sturdiness\":%u}"
                "}}",
                ship->level_stats.levels[SHIP_ATTR_WEIGHT],
                ship->level_stats.levels[SHIP_ATTR_RESISTANCE],
                ship->level_stats.levels[SHIP_ATTR_DAMAGE],
                ship->level_stats.levels[SHIP_ATTR_CREW],
                ship->level_stats.levels[SHIP_ATTR_STURDINESS],
                cur_xp,
                (unsigned)ship_level_max_crew(&ship->level_stats),
                cur_tp, cur_tp,
                SHIP_LEVEL_TOTAL_POINT_CAP,
                cur_tp < SHIP_LEVEL_TOTAL_POINT_CAP ? SHIP_LEVEL_XP_BASE * (cur_tp + 1u) : 0u,
                ship_attr_point_cap(SHIP_ATTR_WEIGHT),
                ship_attr_point_cap(SHIP_ATTR_RESISTANCE),
                ship_attr_point_cap(SHIP_ATTR_DAMAGE),
                ship_attr_point_cap(SHIP_ATTR_CREW),
                ship_attr_point_cap(SHIP_ATTR_STURDINESS));

            const ClaimFlag* cf = NULL;
            for (int _fi = 0; _fi < MAX_CLAIM_FLAGS; _fi++) {
                if (snap->claim_flags[_fi].active && snap->claim_flags[_fi].ship_id == ship->id) {
                    cf = &snap->claim_flags[_fi];
                    break;
                }
            }
            if (cf && offset < (int)sizeof(ship_entry) - 200) {
                if (offset > 0 && ship_entry[offset - 1] == '}') offset--;
                offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                    ",\"claimFlag\":{\"planterId\":%u,\"planterCompany\":%u,"
                    "\"progressMs\":%.0f,\"totalMs\":%u,\"contested\":%s,"
                    "\"localX\":%.1f,\"localY\":%.1f}}",
                    (unsigned)cf->planter_id, (unsigned)cf->planter_company,
                    cf->progress_ms, FLAG_CLAIM_DURATION_MS,
                    cf->contested ? "true" : "false",
                    cf->local_x, cf->local_y);
            }

            int _aoi_s = ships_offset;
            int n = snprintf(out->ships_json + ships_offset,
                             sizeof(out->ships_json) - (size_t)(ships_offset < (int)sizeof(out->ships_json) ? ships_offset : (int)sizeof(out->ships_json)-1),
                             "%s", ship_entry);
            if (n > 0) ships_offset += n;
            if (ships_offset >= (int)sizeof(out->ships_json) - 1) ships_offset = (int)sizeof(out->ships_json) - 1;
            if (out->aoi_ship_count < MAX_SHIPS && n > 0) {
                int _idx = out->aoi_ship_count++;
                out->aoi_ship_px[_idx] = pos_x;
                out->aoi_ship_py[_idx] = pos_y;
                out->aoi_ship_id[_idx] = ship->id;
                out->aoi_ship_start[_idx] = _aoi_s;
                out->aoi_ship_len[_idx] = n;
                snap_ship_lut_set_aoi_idx(lut, (uint16_t)ship->id, (uint16_t)_idx);
            }
            first_ship = false;
        }
    } else {
        int _sc = snap->ship_count;
        if (_sc < 0) _sc = 0;
        if (_sc > MAX_SIMPLE_SHIPS) _sc = MAX_SIMPLE_SHIPS;
        for (int s = 0; s < _sc; s++) {
            if (!snap->ships[s].active) continue;
            if (ships_offset >= (int)sizeof(out->ships_json) - 32) {
                log_warn("⚠️  ships_json near capacity (%d/%zu) — skipping remaining simple ships",
                         ships_offset, sizeof(out->ships_json));
                break;
            }
            if (!first_ship) {
                if (ships_offset < (int)sizeof(out->ships_json) - 1)
                    out->ships_json[ships_offset++] = ',';
            }
            char ship_entry[16384];
            int offset = snprintf(ship_entry, sizeof(ship_entry),
                    "{\"id\":%u,\"seq\":%u,\"name\":\"%s\",\"x\":%.1f,\"y\":%.1f,\"rotation\":%.3f,"
                    "\"velocity_x\":%.2f,\"velocity_y\":%.2f,\"angular_velocity\":%.3f,"
                    "\"rudder_angle\":%.3f,"
                    "\"company\":%u,\"shipType\":%u,"
                    "\"ammo\":%u,\"infiniteAmmo\":%s,\"modules\":[",
                    snap->ships[s].ship_id, snap->ships[s].ship_seq, snap->ships[s].ship_name,
                    snap->ships[s].x, snap->ships[s].y, snap->ships[s].rotation,
                    snap->ships[s].velocity_x, snap->ships[s].velocity_y, snap->ships[s].angular_velocity,
                    0.0f,
                    snap->ships[s].company_id, snap->ships[s].ship_type,
                    snap->ships[s].cannon_ammo, snap->ships[s].infinite_ammo ? "true" : "false");
            for (int m = 0; m < snap->ships[s].module_count && offset < (int)sizeof(ship_entry) - 200; m++) {
                const ShipModule* module = &snap->ships[s].modules[m];
                float module_x = SERVER_TO_CLIENT(Q16_TO_FLOAT(module->local_pos.x));
                float module_y = SERVER_TO_CLIENT(Q16_TO_FLOAT(module->local_pos.y));
                float module_rot = Q16_TO_FLOAT(module->local_rot);
                if (module->type_id == MODULE_TYPE_MAST) {
                    float sail_angle = Q16_TO_FLOAT(module->data.mast.angle);
                    float wind_eff   = Q16_TO_FLOAT(module->data.mast.wind_efficiency);
                    float fh         = Q16_TO_FLOAT(module->data.mast.fiber_health);
                    float fhmax      = Q16_TO_FLOAT(module->data.mast.fiber_max_health);
                    offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                        "%s{\"id\":%u,\"typeId\":%u,\"x\":%.1f,\"y\":%.1f,\"rotation\":%.2f,\"openness\":%u,\"sailAngle\":%.3f,\"windEfficiency\":%.3f,\"fiberHealth\":%.0f,\"fiberMaxHealth\":%.0f}",
                        m > 0 ? "," : "", module->id, module->type_id,
                        module_x, module_y, module_rot, module->data.mast.openness, sail_angle, wind_eff,
                        fh, fhmax);
                } else if (module->type_id == MODULE_TYPE_CANNON) {
                    float aim_direction = Q16_TO_FLOAT(module->data.cannon.aim_direction);
                    offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                        "%s{\"id\":%u,\"typeId\":%u,\"x\":%.1f,\"y\":%.1f,\"rotation\":%.2f,\"aimDir\":%.3f,\"state\":%u}",
                        m > 0 ? "," : "", module->id, module->type_id,
                        module_x, module_y, module_rot, aim_direction,
                        (unsigned)module->state_bits);
                } else if (module->type_id == MODULE_TYPE_SWIVEL) {
                    float aim_dir = Q16_TO_FLOAT(module->data.swivel.aim_direction);
                    offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                        "%s{\"id\":%u,\"typeId\":%u,\"x\":%.1f,\"y\":%.1f,\"rotation\":%.2f,\"aimDir\":%.3f,\"state\":%u}",
                        m > 0 ? "," : "", module->id, module->type_id,
                        module_x, module_y, module_rot, aim_dir,
                        (unsigned)module->state_bits);
                } else if (module->type_id == MODULE_TYPE_HELM || module->type_id == MODULE_TYPE_STEERING_WHEEL) {
                    float wheel_rot = Q16_TO_FLOAT(module->data.helm.wheel_rotation);
                    offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                        "%s{\"id\":%u,\"typeId\":%u,\"x\":%.1f,\"y\":%.1f,\"rotation\":%.2f,\"wheelRot\":%.3f,\"occupied\":%s,\"state\":%u}",
                        m > 0 ? "," : "", module->id, module->type_id,
                        module_x, module_y, module_rot, wheel_rot,
                        (module->data.helm.occupied_by != 0) ? "true" : "false",
                        (unsigned)module->state_bits);
                } else if (module->type_id == MODULE_TYPE_CHEST) {
                    offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                        "%s{\"id\":%u,\"typeId\":%u,\"x\":%.1f,\"y\":%.1f,\"rotation\":%.2f,\"state\":%u"
                        ",\"wood\":%u,\"fiber\":%u,\"metal\":%u,\"stone\":%u}",
                        m > 0 ? "," : "", module->id, module->type_id,
                        module_x, module_y, module_rot, (unsigned)module->state_bits,
                        (unsigned)module->data.chest.wood,
                        (unsigned)module->data.chest.fiber,
                        (unsigned)module->data.chest.metal,
                        (unsigned)module->data.chest.stone);
                } else {
                    offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset,
                        "%s{\"id\":%u,\"typeId\":%u,\"x\":%.1f,\"y\":%.1f,\"rotation\":%.2f,\"state\":%u}",
                        m > 0 ? "," : "", module->id, module->type_id,
                        module_x, module_y, module_rot, (unsigned)module->state_bits);
                }
            }
            offset += snprintf(ship_entry + offset, sizeof(ship_entry) - offset, "]}");
            int _aoi_s2 = ships_offset;
            int n2 = snprintf(out->ships_json + ships_offset,
                              sizeof(out->ships_json) - (size_t)(ships_offset < (int)sizeof(out->ships_json) ? ships_offset : (int)sizeof(out->ships_json)-1),
                              "%s", ship_entry);
            if (n2 > 0) ships_offset += n2;
            if (ships_offset >= (int)sizeof(out->ships_json) - 1) ships_offset = (int)sizeof(out->ships_json) - 1;
            if (out->aoi_ship_count < MAX_SHIPS && n2 > 0) {
                int _idx = out->aoi_ship_count++;
                out->aoi_ship_px[_idx] = snap->ships[s].x;
                out->aoi_ship_py[_idx] = snap->ships[s].y;
                out->aoi_ship_id[_idx] = snap->ships[s].ship_id;
                out->aoi_ship_start[_idx] = _aoi_s2;
                out->aoi_ship_len[_idx] = n2;
                snap_ship_lut_set_aoi_idx(lut, snap->ships[s].ship_id, (uint16_t)_idx);
            }
            first_ship = false;
        }
    }
    if (ships_offset < (int)sizeof(out->ships_json) - 1)
        out->ships_json[ships_offset++] = ']';
    out->ships_json[ships_offset] = '\0';
    out->ships_len = ships_offset;
}

static void* blob_worker_main(void* arg) {
    (void)arg;
    SharedBlobSnapshot local_job;
    SharedBlobOutput local_out;

    pthread_mutex_lock(&g_blob_worker.mtx);
    while (g_blob_worker.running) {
        while (g_blob_worker.running && !g_blob_worker.has_job) {
            pthread_cond_wait(&g_blob_worker.cv, &g_blob_worker.mtx);
        }
        if (!g_blob_worker.running) break;

        local_job = g_blob_worker.job;
        g_blob_worker.has_job = false;
        pthread_mutex_unlock(&g_blob_worker.mtx);

        uint64_t _t0 = get_time_us();
        build_shared_blobs_from_snapshot(&local_job, &local_out, &g_blob_worker_lut);
        uint64_t _dt = get_time_us() - _t0;

        pthread_mutex_lock(&g_blob_worker.mtx);
        g_blob_worker.output = local_out;
        g_blob_worker.has_output = true;
        g_blob_worker.jobs_completed++;
        g_blob_worker.last_build_us = _dt;
        if (_dt > g_blob_worker.max_build_us) g_blob_worker.max_build_us = _dt;
    }
    pthread_mutex_unlock(&g_blob_worker.mtx);
    return NULL;
}

static int blob_worker_start(void) {
    if (g_blob_worker.started) return 0;
    if (pthread_mutex_init(&g_blob_worker.mtx, NULL) != 0) return -1;
    if (pthread_cond_init(&g_blob_worker.cv, NULL) != 0) {
        pthread_mutex_destroy(&g_blob_worker.mtx);
        return -1;
    }
    g_blob_worker.running = true;
    g_blob_worker.started = true;
    g_blob_worker.has_job = false;
    g_blob_worker.has_output = false;
    if (pthread_create(&g_blob_worker.thread, NULL, blob_worker_main, NULL) != 0) {
        g_blob_worker.running = false;
        g_blob_worker.started = false;
        pthread_cond_destroy(&g_blob_worker.cv);
        pthread_mutex_destroy(&g_blob_worker.mtx);
        return -1;
    }
    return 0;
}

static void blob_worker_stop(void) {
    if (!g_blob_worker.started) return;
    pthread_mutex_lock(&g_blob_worker.mtx);
    g_blob_worker.running = false;
    pthread_cond_broadcast(&g_blob_worker.cv);
    pthread_mutex_unlock(&g_blob_worker.mtx);
    pthread_join(g_blob_worker.thread, NULL);
    pthread_cond_destroy(&g_blob_worker.cv);
    pthread_mutex_destroy(&g_blob_worker.mtx);
    memset(&g_blob_worker, 0, sizeof(g_blob_worker));
}

static void blob_worker_submit_snapshot(uint32_t current_time) {
    if (!g_blob_worker.started) return;
    pthread_mutex_lock(&g_blob_worker.mtx);
    g_blob_worker.job.current_time = current_time;
    g_blob_worker.job.tick = global_sim ? global_sim->tick : 0;
    memcpy(g_blob_worker.job.tombstones, tombstones, sizeof(tombstones));
    memcpy(g_blob_worker.job.dropped_items, dropped_items, sizeof(dropped_items));
    if (dynamic_company_count > 0)
        memcpy(g_blob_worker.job.dynamic_companies, dynamic_companies,
               (size_t)dynamic_company_count * sizeof(dynamic_companies[0]));
    else
        memset(g_blob_worker.job.dynamic_companies, 0, sizeof(g_blob_worker.job.dynamic_companies));
    g_blob_worker.job.dynamic_company_count = dynamic_company_count;
    /* Copy only active ship slots (not the full 200-entry array).
     * SimpleShip is ~8-10 KB each; copying 200 entries even when 8 are active
     * was wasting ~1.6 MB of memcpy bandwidth per tick on the hot path. */
    g_blob_worker.job.ship_count = ship_count;
    if (ship_count > 0)
        memcpy(g_blob_worker.job.ships, ships,
               (size_t)ship_count * sizeof(ships[0]));
    for (int _bpi = 0; _bpi < WS_MAX_CLIENTS; _bpi++) {
        if (players[_bpi].active)
            copy_player_to_blob(&players[_bpi], &g_blob_worker.job.players[_bpi]);
        else
            g_blob_worker.job.players[_bpi].active = false;
    }
    g_blob_worker.job.sim_ship_count = 0;
    if (global_sim) {
        uint16_t _ss = global_sim->ship_count;
        if (_ss > MAX_SHIPS) _ss = MAX_SHIPS;
        g_blob_worker.job.sim_ship_count = _ss;
        memcpy(g_blob_worker.job.sim_ships, global_sim->ships,
               (size_t)_ss * sizeof(struct Ship));
    }
    g_blob_worker.job.projectile_count = 0;
    if (global_sim) {
        uint16_t _pc = global_sim->projectile_count;
        if (_pc > MAX_PROJECTILES) _pc = MAX_PROJECTILES;
        g_blob_worker.job.projectile_count = _pc;
        memcpy(g_blob_worker.job.projectiles, global_sim->projectiles,
               (size_t)_pc * sizeof(struct Projectile));
    }
    /* Copy only active NPC slots (not the full 512-entry array).
     * WorldNpc is ~420 B each; copying all 512 even when 80 are active
     * was wasting ~215 KB per tick. */
    g_blob_worker.job.world_npc_count = world_npc_count;
    if (world_npc_count > 0)
        memcpy(g_blob_worker.job.world_npcs, world_npcs,
               (size_t)world_npc_count * sizeof(world_npcs[0]));
    memcpy(g_blob_worker.job.claim_flags, claim_flags, sizeof(claim_flags));
    g_blob_worker.has_job = true;
    g_blob_worker.jobs_submitted++;
    pthread_cond_signal(&g_blob_worker.cv);
    pthread_mutex_unlock(&g_blob_worker.mtx);
}

static bool blob_worker_try_get_output(SharedBlobOutput* out) {
    bool ok = false;
    if (!g_blob_worker.started || !out) return false;
    pthread_mutex_lock(&g_blob_worker.mtx);
    if (g_blob_worker.has_output) {
        *out = g_blob_worker.output;
        ok = true;
    }
    pthread_mutex_unlock(&g_blob_worker.mtx);
    return ok;
}

static void blob_worker_note_fallback_build(void) {
    if (!g_blob_worker.started) return;
    pthread_mutex_lock(&g_blob_worker.mtx);
    g_blob_worker.fallback_sync_builds++;
    pthread_mutex_unlock(&g_blob_worker.mtx);
}

static void blob_worker_log_stats(void) {
    if (!g_blob_worker.started) return;
    pthread_mutex_lock(&g_blob_worker.mtx);
    uint64_t _submitted = g_blob_worker.jobs_submitted;
    uint64_t _completed = g_blob_worker.jobs_completed;
    uint64_t _fallbacks = g_blob_worker.fallback_sync_builds;
    uint64_t _last_us   = g_blob_worker.last_build_us;
    uint64_t _max_us    = g_blob_worker.max_build_us;
    pthread_mutex_unlock(&g_blob_worker.mtx);
    uint64_t _lag = (_submitted >= _completed) ? (_submitted - _completed) : 0;
    log_info("🧵 blob-worker stats: submitted=%llu completed=%llu lag=%llu fallback_sync=%llu last_build=%lluus max_build=%lluus",
             (unsigned long long)_submitted,
             (unsigned long long)_completed,
             (unsigned long long)_lag,
             (unsigned long long)_fallbacks,
             (unsigned long long)_last_us,
             (unsigned long long)_max_us);
}

/**
 * Called on every authoritative player death.
 * 1. Copies all inventory items into a new tombstone.
 * 2. Wipes the player's inventory.
 * 3. Broadcasts tombstone_spawned to all clients.
 */

/**
 * Returns total flat armour value for a player based on equipped cloth gear.
 * Damage is reduced by this amount (minimum 1 per hit).
 */
static int player_armor_value(const WebSocketPlayer* p) {
    int v = 0;
    const PlayerEquipment* eq = &p->inventory.equipment;
    if (eq->helm  == ITEM_CLOTH_HAT)    v += 5;
    if (eq->torso == ITEM_CLOTH_SHIRT)  v += 20;
    if (eq->torso == ITEM_CLOTH_ARMOR)  v += 5;   /* legacy generic cloth */
    if (eq->legs  == ITEM_CLOTH_PANTS)  v += 15;
    if (eq->feet  == ITEM_CLOTH_SHOES)  v += 8;
    if (eq->hands == ITEM_CLOTH_GLOVES) v += 7;
    return v;
}

/** Lightweight friendly-fleet snapshot for the respawn/world map (no full ship modules). */
void send_respawn_map_to_player(WebSocketPlayer* player) {
    if (!player || player->company_id == 0) return;

    struct WebSocketClient* client = NULL;
    for (int i = 0; i < WS_MAX_CLIENTS; i++) {
        if (ws_server.clients[i].connected &&
            ws_server.clients[i].handshake_complete &&
            ws_server.clients[i].player_id == player->player_id) {
            client = &ws_server.clients[i];
            break;
        }
    }
    if (!client) return;

    static char json[65536];
    int off = snprintf(json, sizeof(json), "{\"type\":\"respawn_map\",\"ships\":[");
    bool first_ship = true;

    for (int si = 0; si < ship_count && off < (int)sizeof(json) - 512; si++) {
        SimpleShip* ss = &ships[si];
        if (!ss->active) continue;
        if (ss->company_id != player->company_id) continue;
        if (ss->ship_type == SHIP_TYPE_GHOST) continue;

        if (!first_ship) json[off++] = ',';
        first_ship = false;

        off += snprintf(json + off, sizeof(json) - (size_t)off,
            "{\"id\":%u,\"name\":\"%s\",\"x\":%.1f,\"y\":%.1f,\"rotation\":%.4f,\"beds\":[",
            ss->ship_id, ss->ship_name, ss->x, ss->y, ss->rotation);

        bool first_bed = true;
        struct Ship* sim = find_sim_ship(ss->ship_id);
        if (sim) {
            for (uint8_t m = 0; m < sim->module_count && off < (int)sizeof(json) - 128; m++) {
                ShipModule* mod = &sim->modules[m];
                if (mod->type_id != MODULE_TYPE_BED) continue;
                if (mod->state_bits & MODULE_STATE_DESTROYED) continue;
                float blx = SERVER_TO_CLIENT(Q16_TO_FLOAT(mod->local_pos.x));
                float bly = SERVER_TO_CLIENT(Q16_TO_FLOAT(mod->local_pos.y));
                if (!first_bed) json[off++] = ',';
                first_bed = false;
                off += snprintf(json + off, sizeof(json) - (size_t)off,
                    "{\"moduleId\":%u,\"localX\":%.1f,\"localY\":%.1f}",
                    mod->id, blx, bly);
            }
        }
        off += snprintf(json + off, sizeof(json) - (size_t)off, "]}");
    }
    off += snprintf(json + off, sizeof(json) - (size_t)off, "]}");

    static char frame[65552];
    size_t flen = websocket_create_frame(WS_OPCODE_TEXT, json, (size_t)off, frame, sizeof(frame));
    if (flen > 0) send(client->fd, frame, flen, 0);
}

void player_die(WebSocketPlayer* player) {
    /* Check whether the player has any items worth dropping */
    bool has_items = false;
    for (int s = 0; s < INVENTORY_SLOTS; s++) {
        if (player->inventory.slots[s].item != ITEM_NONE &&
            player->inventory.slots[s].quantity > 0) { has_items = true; break; }
    }
    if (!has_items) {
        /* also check worn equipment */
        has_items = (player->inventory.equipment.helm   != ITEM_NONE ||
                     player->inventory.equipment.torso  != ITEM_NONE ||
                     player->inventory.equipment.legs   != ITEM_NONE ||
                     player->inventory.equipment.feet   != ITEM_NONE ||
                     player->inventory.equipment.hands  != ITEM_NONE ||
                     player->inventory.equipment.shield != ITEM_NONE);
    }

    /* Find a free tombstone slot */
    Tombstone* t = NULL;
    if (has_items) {
        for (int i = 0; i < (int)MAX_TOMBSTONES; i++) {
            if (!tombstones[i].active) { t = &tombstones[i]; break; }
        }
    }

    if (t) {
        t->id = next_tombstone_id++;
        if (next_tombstone_id == 0) next_tombstone_id = 1;
        t->x = player->x;
        t->y = player->y;
        /* Attach to ship if player is currently aboard one */
        if (player->parent_ship_id != 0) {
            const SimpleShip* ship = find_ship(player->parent_ship_id);
            if (ship && ship->active) {
                t->ship_id = player->parent_ship_id;
                ship_world_to_local(ship, player->x, player->y, &t->local_x, &t->local_y);
            } else {
                t->ship_id = 0;
                t->local_x = t->local_y = 0.0f;
            }
        } else {
            t->ship_id = 0;
            t->local_x = t->local_y = 0.0f;
        }
        snprintf(t->owner_name, sizeof(t->owner_name), "%s", player->name);
        t->inventory      = player->inventory;  /* full struct copy */
        t->spawn_time_ms  = get_time_ms();
        t->active         = true;

        /* Broadcast tombstone_spawned ─────────────────────────────────── */
        char msg[1024];
        int off = snprintf(msg, sizeof(msg),
            "{\"type\":\"tombstone_spawned\",\"id\":%u,\"x\":%.1f,\"y\":%.1f,"
            "\"ownerName\":\"%s\",\"ttlMs\":%u,"
            "\"equip\":{\"helm\":%d,\"torso\":%d,\"legs\":%d,"
                       "\"feet\":%d,\"hands\":%d,\"shield\":%d},\"slots\":[",
            t->id, t->x, t->y, t->owner_name, TOMBSTONE_TTL_MS,
            (int)t->inventory.equipment.helm,  (int)t->inventory.equipment.torso,
            (int)t->inventory.equipment.legs,  (int)t->inventory.equipment.feet,
            (int)t->inventory.equipment.hands, (int)t->inventory.equipment.shield);
        for (int s = 0; s < INVENTORY_SLOTS && off < (int)sizeof(msg) - 8; s++) {
            if (s > 0) msg[off++] = ',';
            off += snprintf(msg + off, sizeof(msg) - off, "[%d,%d]",
                (int)t->inventory.slots[s].item,
                (int)t->inventory.slots[s].quantity);
        }
        off += snprintf(msg + off, sizeof(msg) - off, "]}");
        websocket_server_broadcast(msg);
        log_info("⚰️  Tombstone %u spawned for %s at (%.1f,%.1f)",
                 t->id, t->owner_name, t->x, t->y);
    }

    /* Wipe player inventory regardless of whether a tombstone was created */
    memset(&player->inventory, 0, sizeof(PlayerInventory));
    player->inventory.active_slot = 255; /* sentinel: nothing equipped */

    /* If the player was at the helm, release all steering inputs so the ship
     * doesn't keep turning or reversing with no one at the wheel. */
    if (player->is_mounted && player->controlling_ship_id != 0) {
        helm_release_controls(player->controlling_ship_id);
        /* Clear occupancy on the helm module itself */
        SimpleShip* ctrl_ship = find_ship(player->controlling_ship_id);
        if (ctrl_ship) {
            ShipModule* hmod = find_module_by_id(ctrl_ship, player->mounted_module_id);
            if (hmod && (hmod->type_id == MODULE_TYPE_HELM ||
                         hmod->type_id == MODULE_TYPE_STEERING_WHEEL)) {
                hmod->data.helm.occupied_by = 0;
                hmod->state_bits &= ~MODULE_STATE_OCCUPIED;
            }
        }
        player->is_mounted          = false;
        player->mounted_module_id   = 0;
        player->controlling_ship_id = 0;
    }

    /* Detach any active grapple hook on death.  The dead player's slot stays
     * active (is_dead=true), so the per-tick !owner->active cleanup never fires,
     * and an ATTACHED hook has no timeout — without this a dead player would keep
     * reeling a target (or their own corpse) toward a ship indefinitely. */
    {
        int _slot = (int)(player - players);
        if (_slot >= 0 && _slot < WS_MAX_CLIENTS && grapple_hooks[_slot].active) {
            grapple_detach(_slot);
        }
    }

    player->health  = 0;
    player->is_dead = true;
    player->fire_timer_ms = 0; /* extinguish any active burn on death */

    send_respawn_map_to_player(player);
}

/**
 * Handle a collect_tombstone request from a client.
 * Player must be within 80 px of the tombstone.
 * Items are transferred into the player's inventory; tombstone is removed.
 */
static void handle_collect_tombstone(WebSocketPlayer* player,
                                     struct WebSocketClient* client,
                                     const char* payload) {
    uint32_t tomb_id = 0;
    const char* p_id = strstr(payload, "\"id\":");
    if (p_id) tomb_id = (uint32_t)atoi(p_id + 5);

    /* Locate tombstone */
    Tombstone* t = NULL;
    for (int i = 0; i < (int)MAX_TOMBSTONES; i++) {
        if (tombstones[i].active && tombstones[i].id == tomb_id) {
            t = &tombstones[i]; break;
        }
    }
    if (!t) {
        char resp[128];
        snprintf(resp, sizeof(resp),
            "{\"type\":\"tombstone_collect_fail\",\"reason\":\"not_found\",\"id\":%u}", tomb_id);
        char frame[192];
        size_t fl = websocket_create_frame(WS_OPCODE_TEXT, resp, strlen(resp), frame, sizeof(frame));
        if (fl > 0) send(client->fd, frame, fl, 0);
        return;
    }

    /* Range check: 80 px */
    float tx, ty;
    tombstone_world_pos(t, &tx, &ty);
    float dx = player->x - tx;
    float dy = player->y - ty;
    if (dx * dx + dy * dy > 80.0f * 80.0f) {
        char resp[128];
        snprintf(resp, sizeof(resp),
            "{\"type\":\"tombstone_collect_fail\",\"reason\":\"too_far\",\"id\":%u}", tomb_id);
        char frame[192];
        size_t fl = websocket_create_frame(WS_OPCODE_TEXT, resp, strlen(resp), frame, sizeof(frame));
        if (fl > 0) send(client->fd, frame, fl, 0);
        return;
    }

    /* Transfer hotbar slots */
    for (int s = 0; s < INVENTORY_SLOTS; s++) {
        if (t->inventory.slots[s].item != ITEM_NONE && t->inventory.slots[s].quantity > 0)
            craft_grant(player, t->inventory.slots[s].item,
                        (int)t->inventory.slots[s].quantity);
    }
    /* Transfer worn equipment */
    if (t->inventory.equipment.helm   != ITEM_NONE) craft_grant(player, t->inventory.equipment.helm,   1);
    if (t->inventory.equipment.torso  != ITEM_NONE) craft_grant(player, t->inventory.equipment.torso,  1);
    if (t->inventory.equipment.legs   != ITEM_NONE) craft_grant(player, t->inventory.equipment.legs,   1);
    if (t->inventory.equipment.feet   != ITEM_NONE) craft_grant(player, t->inventory.equipment.feet,   1);
    if (t->inventory.equipment.hands  != ITEM_NONE) craft_grant(player, t->inventory.equipment.hands,  1);
    if (t->inventory.equipment.shield != ITEM_NONE) craft_grant(player, t->inventory.equipment.shield, 1);

    /* Remove tombstone and broadcast */
    t->active = false;
    char msg[128];
    snprintf(msg, sizeof(msg),
        "{\"type\":\"tombstone_collected\",\"id\":%u,\"playerId\":%u}",
        tomb_id, player->player_id);
    websocket_server_broadcast(msg);
    log_info("⚰️  Tombstone %u collected by player %u (%s)",
             tomb_id, player->player_id, player->name);
}

/* ── Dropped-item helpers ─────────────────────────────────────────────────── */

/* Helper: frame + send a short text message to one client. */
static void ws_send_text(int fd, const char* msg) {
    char frame[256];
    size_t fl = websocket_create_frame(WS_OPCODE_TEXT, msg, strlen(msg), frame, sizeof(frame));
    if (fl > 0) send(fd, frame, fl, 0);
}

/* Helper: serialize tombstone inventory and send tombstone_items to one client. */
static void send_tombstone_items(struct WebSocketClient* client, Tombstone* t) {
    char msg[2048];
    int off = snprintf(msg, sizeof(msg),
        "{\"type\":\"tombstone_items\",\"id\":%u,\"ownerName\":\"%s\","
        "\"equip\":{\"helm\":%d,\"torso\":%d,\"legs\":%d,"
                   "\"feet\":%d,\"hands\":%d,\"shield\":%d},\"slots\":[",
        t->id, t->owner_name,
        (int)t->inventory.equipment.helm,  (int)t->inventory.equipment.torso,
        (int)t->inventory.equipment.legs,  (int)t->inventory.equipment.feet,
        (int)t->inventory.equipment.hands, (int)t->inventory.equipment.shield);
    for (int s = 0; s < INVENTORY_SLOTS && off < (int)sizeof(msg) - 16; s++) {
        if (s > 0) msg[off++] = ',';
        off += snprintf(msg + off, sizeof(msg) - off, "[%d,%d]",
            (int)t->inventory.slots[s].item,
            (int)t->inventory.slots[s].quantity);
    }
    off += snprintf(msg + off, sizeof(msg) - off, "]}");
    char frame[2200];
    size_t fl = websocket_create_frame(WS_OPCODE_TEXT, msg, (size_t)off, frame, sizeof(frame));
    if (fl > 0) send(client->fd, frame, fl, 0);
}

/**
 * Handle tombstone_open: player opened the tombstone menu.
 * Range-checks and sends back tombstone_items to just this client.
 */
static void handle_tombstone_open(WebSocketPlayer* player,
                                   struct WebSocketClient* client,
                                   const char* payload) {
    uint32_t tomb_id = 0;
    const char* p_id = strstr(payload, "\"id\":");
    if (p_id) tomb_id = (uint32_t)atoi(p_id + 5);

    Tombstone* t = NULL;
    for (int i = 0; i < (int)MAX_TOMBSTONES; i++) {
        if (tombstones[i].active && tombstones[i].id == tomb_id) {
            t = &tombstones[i]; break;
        }
    }
    if (!t) {
        char resp[128];
        snprintf(resp, sizeof(resp),
            "{\"type\":\"tombstone_collect_fail\",\"reason\":\"not_found\",\"id\":%u}", tomb_id);
        ws_send_text(client->fd, resp);
        return;
    }
    float dx = player->x - t->x, dy = player->y - t->y;
    {
        float tx, ty;
        tombstone_world_pos(t, &tx, &ty);
        dx = player->x - tx;
        dy = player->y - ty;
    }
    if (dx * dx + dy * dy > 80.0f * 80.0f) {
        char resp[128];
        snprintf(resp, sizeof(resp),
            "{\"type\":\"tombstone_collect_fail\",\"reason\":\"too_far\",\"id\":%u}", tomb_id);
        ws_send_text(client->fd, resp);
        return;
    }
    send_tombstone_items(client, t);
}

/**
 * Handle tombstone_take_slot: player dragged one slot out of the tombstone.
 * Grants that item to the player, clears the tombstone slot.
 * If tombstone becomes empty, removes it and broadcasts tombstone_collected.
 * Otherwise sends updated tombstone_items back to the requesting client.
 */
static void handle_tombstone_take_slot(WebSocketPlayer* player,
                                        struct WebSocketClient* client,
                                        const char* payload) {
    uint32_t tomb_id = 0;
    int slot = -1;
    const char* p_id = strstr(payload, "\"id\":");
    const char* p_sl = strstr(payload, "\"slot\":");
    if (p_id) tomb_id = (uint32_t)atoi(p_id + 5);
    if (p_sl) slot    = atoi(p_sl + 7);

    if (slot < 0 || slot >= INVENTORY_SLOTS) return;

    Tombstone* t = NULL;
    for (int i = 0; i < (int)MAX_TOMBSTONES; i++) {
        if (tombstones[i].active && tombstones[i].id == tomb_id) {
            t = &tombstones[i]; break;
        }
    }
    if (!t) return;
    {
        float tx, ty;
        tombstone_world_pos(t, &tx, &ty);
        float dx = player->x - tx, dy = player->y - ty;
        if (dx * dx + dy * dy > 80.0f * 80.0f) return;
    }

    InventorySlot* isl = &t->inventory.slots[slot];
    if (isl->item == ITEM_NONE || isl->quantity == 0) return;

    craft_grant(player, isl->item, (int)isl->quantity);
    isl->item     = ITEM_NONE;
    isl->quantity = 0;

    /* Check if tombstone is now completely empty */
    bool any_left = false;
    for (int s = 0; s < INVENTORY_SLOTS; s++) {
        if (t->inventory.slots[s].item != ITEM_NONE && t->inventory.slots[s].quantity > 0)
            { any_left = true; break; }
    }
    if (!any_left) {
        if (t->inventory.equipment.helm   != ITEM_NONE ||
            t->inventory.equipment.torso  != ITEM_NONE ||
            t->inventory.equipment.legs   != ITEM_NONE ||
            t->inventory.equipment.feet   != ITEM_NONE ||
            t->inventory.equipment.hands  != ITEM_NONE ||
            t->inventory.equipment.shield != ITEM_NONE)
            any_left = true;
    }

    if (!any_left) {
        t->active = false;
        char msg[128];
        snprintf(msg, sizeof(msg),
            "{\"type\":\"tombstone_collected\",\"id\":%u,\"playerId\":%u}",
            tomb_id, player->player_id);
        websocket_server_broadcast(msg);
        log_info("⚰️  Tombstone %u emptied slot-by-slot by player %u", tomb_id, player->player_id);
        return;
    }

    /* Send refreshed tombstone contents back to this client */
    send_tombstone_items(client, t);
}

static void handle_chat_message(WebSocketPlayer* player,
                                 const char* payload)
{
    /* {"type":"chat_message","channel":"global","text":"hello world"} */
    char channel[16] = "global";
    char text[256]   = {0};

    /* Parse channel */
    const char* pc = strstr(payload, "\"channel\":");
    if (pc) {
        const char* qs = strchr(pc + 10, '"');
        if (qs) {
            const char* qe = strchr(qs + 1, '"');
            if (qe) {
                size_t len = (size_t)(qe - qs - 1);
                if (len >= sizeof(channel)) len = sizeof(channel) - 1;
                memcpy(channel, qs + 1, len);
                channel[len] = '\0';
            }
        }
    }

    /* Parse text */
    const char* pt = strstr(payload, "\"text\":");
    if (pt) {
        const char* qs = strchr(pt + 7, '"');
        if (qs) {
            /* Walk forward and unescape basic \" sequences */
            size_t pos = 0;
            const char* c = qs + 1;
            while (*c && pos < sizeof(text) - 1) {
                if (*c == '\\' && *(c + 1) == '"') {
                    text[pos++] = '"'; c += 2;
                } else if (*c == '"') {
                    break; /* end of string */
                } else {
                    text[pos++] = *c++;
                }
            }
            text[pos] = '\0';
        }
    }

    if (text[0] == '\0') return; /* silently ignore empty messages */

    /* Sanitise channel to known values */
    const char* valid[] = {"global", "local", "company", "alliance"};
    bool ch_ok = false;
    for (int i = 0; i < 4; i++) if (strcmp(channel, valid[i]) == 0) { ch_ok = true; break; }
    if (!ch_ok) strcpy(channel, "global");

    /* Build broadcast JSON */
    char msg[512];
    snprintf(msg, sizeof(msg),
        "{\"type\":\"chat_broadcast\","
        "\"channel\":\"%s\","
        "\"senderId\":%u,"
        "\"senderName\":\"%s\","
        "\"text\":\"%s\"}",
        channel, player->player_id, player->name, text);

    /* Deliver to appropriate recipients */
    if (strcmp(channel, "global") == 0) {
        websocket_server_broadcast(msg);
    } else if (strcmp(channel, "local") == 0) {
        /* Broadcast to players within 1000 world units */
        const float LOCAL_RANGE = 1000.0f;
        for (int i = 0; i < WS_MAX_CLIENTS; i++) {
            if (!players[i].active) continue;
            float dx = players[i].x - player->x;
            float dy = players[i].y - player->y;
            if (dx * dx + dy * dy > LOCAL_RANGE * LOCAL_RANGE) continue;
            for (int ci = 0; ci < WS_MAX_CLIENTS; ci++) {
                if (ws_server.clients[ci].connected
                    && ws_server.clients[ci].player_id == players[i].player_id) {
                    ws_send_text(ws_server.clients[ci].fd, msg);
                    break;
                }
            }
        }
    } else if (strcmp(channel, "company") == 0 || strcmp(channel, "alliance") == 0) {
        /* For alliance, fall back to same company (alliance system not yet implemented) */
        for (int i = 0; i < WS_MAX_CLIENTS; i++) {
            if (!players[i].active) continue;
            if (players[i].company_id != player->company_id) continue;
            for (int ci = 0; ci < WS_MAX_CLIENTS; ci++) {
                if (ws_server.clients[ci].connected
                    && ws_server.clients[ci].player_id == players[i].player_id) {
                    ws_send_text(ws_server.clients[ci].fd, msg);
                    break;
                }
            }
        }
    }

    log_info("💬  [%s] %s: %s", channel, player->name, text);
}

static void handle_drop_item(WebSocketPlayer* player,
                              struct WebSocketClient* client,
                              const char* payload)
{
    int slot = -1;
    const char* ps = strstr(payload, "\"slot\":");
    if (ps) sscanf(ps + 7, "%d", &slot);
    if (slot < 0 || slot >= INVENTORY_SLOTS) {
        ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"invalid_slot\"}");
        return;
    }
    InventorySlot* isl = &player->inventory.slots[slot];
    if (isl->item == ITEM_NONE || isl->quantity == 0) {
        ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"empty_slot\"}");
        return;
    }
    DroppedItem* di = NULL;
    for (int i = 0; i < (int)MAX_DROPPED_ITEMS; i++) {
        if (!dropped_items[i].active) { di = &dropped_items[i]; break; }
    }
    if (!di) {
        ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"world_full\"}");
        return;
    }
    memset(di, 0, sizeof(*di));
    di->id            = next_dropped_item_id++;
    if (next_dropped_item_id == 0) next_dropped_item_id = 1;
    di->item_kind     = (uint8_t)isl->item;
    di->quantity      = isl->quantity;
    place_dropped_item_at_player(di, player);
    di->spawn_time_ms = get_time_ms();
    di->active        = true;
    isl->item     = ITEM_NONE;
    isl->quantity = 0;
    char resp[128];
    snprintf(resp, sizeof(resp),
        "{\"type\":\"message_ack\",\"status\":\"item_dropped\",\"drop_id\":%u}", di->id);
    ws_send_text(client->fd, resp);
    log_info("📦  Player %u dropped item %u qty %u at (%.1f,%.1f) id=%u",
             player->player_id, (unsigned)di->item_kind, (unsigned)di->quantity,
             (double)di->x, (double)di->y, di->id);
}

/* ── Drop a quality blueprint from the player's schematic list ──────────────
 * Message: {"type":"drop_schematic","timestamp":N,"index":N}
 * Clears the PlayerBlueprint slot at `index` from the player's schematics[].
 * The server immediately re-sends the schematic list so the client stays in sync. */

/* Forward declaration — crafting.h is included later in this translation unit. */
void send_schematic_list(WebSocketPlayer* player, struct WebSocketClient* client);
bool schematic_remove_at(WebSocketPlayer* player, int index);

static void handle_drop_schematic(WebSocketPlayer* player,
                                   struct WebSocketClient* client,
                                   const char* payload)
{
    int index = -1;
    const char* pi = strstr(payload, "\"index\":");
    if (pi) sscanf(pi + 8, "%d", &index);

    if (index < 0 || index >= MAX_PLAYER_SCHEMATICS) {
        ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"invalid_schematic_index\"}");
        return;
    }
    if (player->schematics[index].item == 0) {
        ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"empty_schematic_slot\"}");
        return;
    }

    DroppedItem* di = NULL;
    for (int i = 0; i < (int)MAX_DROPPED_ITEMS; i++) {
        if (!dropped_items[i].active) { di = &dropped_items[i]; break; }
    }
    if (!di) {
        ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"world_full\"}");
        return;
    }

    PlayerBlueprint dropped = player->schematics[index];
    schematic_remove_at(player, index);

    memset(di, 0, sizeof(*di));
    di->id               = next_dropped_item_id++;
    if (next_dropped_item_id == 0) next_dropped_item_id = 1;
    di->item_kind        = dropped.item;
    di->quantity         = 1;
    place_dropped_item_at_player(di, player);
    di->spawn_time_ms    = get_time_ms();
    di->active           = true;
    di->is_schematic     = true;
    di->crafts_remaining = dropped.crafts_remaining;
    di->quality          = dropped.quality;

    log_info("📜  Player %u dropped blueprint index %d (item %u) at (%.1f,%.1f) id=%u",
             player->player_id, index, (unsigned)dropped.item,
             (double)di->x, (double)di->y, di->id);

    char resp[128];
    snprintf(resp, sizeof(resp),
        "{\"type\":\"message_ack\",\"status\":\"schematic_dropped\",\"drop_id\":%u}", di->id);
    ws_send_text(client->fd, resp);

    /* Re-send the updated schematic list so the client's UI refreshes. */
    send_schematic_list(player, client);
}

/* ── Drop a resource stack from the player's resource pool ──────────────────
 * Message: {"type":"drop_resources","timestamp":N,"kind":"wood","amount":N}
 * Creates a DroppedItem in the world so other players can pick it up. */
static void handle_drop_resources(WebSocketPlayer* player,
                                   struct WebSocketClient* client,
                                   const char* payload)
{
    /* Parse kind */
    char kind[32] = "";
    const char* kp = strstr(payload, "\"kind\":");
    if (kp) {
        kp += 7;
        while (*kp == ' ' || *kp == '"') kp++;
        int ki = 0;
        while (*kp && *kp != '"' && ki < 31) kind[ki++] = *kp++;
        kind[ki] = '\0';
    }
    /* Parse amount */
    int amount = 0;
    const char* ap = strstr(payload, "\"amount\":");
    if (ap) sscanf(ap + 9, "%d", &amount);

    if (kind[0] == '\0' || amount <= 0) {
        ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"invalid_drop_resources\"}");
        return;
    }

    /* Map kind → resource field and item kind */
    uint16_t* res_field = NULL;
    uint8_t   item_kind = 0;
    if      (strcmp(kind, "wood")  == 0) { res_field = &player->res_wood;  item_kind = ITEM_WOOD;  }
    else if (strcmp(kind, "fiber") == 0) { res_field = &player->res_fiber; item_kind = ITEM_FIBER; }
    else if (strcmp(kind, "metal") == 0) { res_field = &player->res_metal; item_kind = ITEM_METAL; }
    else if (strcmp(kind, "stone") == 0) { res_field = &player->res_stone; item_kind = ITEM_STONE; }
    else {
        ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"unknown_resource_kind\"}");
        return;
    }

    /* Clamp to what the player actually has */
    if (amount > (int)*res_field) amount = (int)*res_field;
    if (amount <= 0) {
        ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"no_resources\"}");
        return;
    }

    /* Find a free dropped-item slot */
    DroppedItem* di = NULL;
    for (int i = 0; i < (int)MAX_DROPPED_ITEMS; i++) {
        if (!dropped_items[i].active) { di = &dropped_items[i]; break; }
    }
    if (!di) {
        ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"world_full\"}");
        return;
    }

    /* Deduct */
    *res_field = (uint16_t)(*res_field - amount);

    /* Spawn the dropped item slightly ahead of the player */
    memset(di, 0, sizeof(*di));
    di->id           = next_dropped_item_id++;
    if (next_dropped_item_id == 0) next_dropped_item_id = 1;
    di->item_kind    = item_kind;
    di->quantity     = (uint16_t)amount;
    place_dropped_item_at_player(di, player);
    di->spawn_time_ms = get_time_ms();
    di->active       = true;

    char resp[128];
    snprintf(resp, sizeof(resp),
        "{\"type\":\"message_ack\",\"status\":\"resources_dropped\",\"drop_id\":%u}", di->id);
    ws_send_text(client->fd, resp);
    log_info("🪵  Player %u dropped %d %s at (%.1f,%.1f) id=%u",
             player->player_id, amount, kind,
             (double)di->x, (double)di->y, di->id);
}

static void handle_pickup_item(WebSocketPlayer* player,
                                struct WebSocketClient* client,
                                const char* payload)
{
    uint32_t item_id = 0;
    const char* pi = strstr(payload, "\"item_id\":");
    if (pi) sscanf(pi + 10, "%u", &item_id);
    if (item_id == 0) {
        ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"invalid_id\"}");
        return;
    }
    DroppedItem* di = NULL;
    for (int i = 0; i < (int)MAX_DROPPED_ITEMS; i++) {
        if (dropped_items[i].active && dropped_items[i].id == item_id) {
            di = &dropped_items[i]; break;
        }
    }
    if (!di) {
        ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"not_found\"}");
        return;
    }
    float item_wx, item_wy;
    dropped_item_world_pos(di, &item_wx, &item_wy);
    float dx = item_wx - player->x;
    float dy = item_wy - player->y;
    if (dx * dx + dy * dy > 80.0f * 80.0f) {
        ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"too_far\"}");
        return;
    }
    if (di->ship_id != 0) {
        if (player->parent_ship_id != di->ship_id ||
            player->deck_level != di->deck_level) {
            ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"too_far\"}");
            return;
        }
    }

    /* ── Quality blueprint schematics go into the schematic store ── */
    if (di->is_schematic) {
        if (!schematic_add(player, (ItemKind)di->item_kind, di->crafts_remaining, &di->quality)) {
            ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"schematic_inventory_full\"}");
            return;
        }
        di->active = false;
        send_schematic_list(player, client);
        char resp[128];
        snprintf(resp, sizeof(resp),
            "{\"type\":\"message_ack\",\"status\":\"schematic_picked_up\"}");
        ws_send_text(client->fd, resp);
        log_info("📜  Player %u picked up schematic drop id %u (item %u, %u crafts)",
                 player->player_id, item_id, (unsigned)di->item_kind,
                 (unsigned)di->crafts_remaining);
        return;
    }

    /* ── Resource items go into the resource pool, not inventory slots ── */
    {
        uint16_t* res_field = NULL;
        if      (di->item_kind == ITEM_WOOD)  res_field = &player->res_wood;
        else if (di->item_kind == ITEM_FIBER) res_field = &player->res_fiber;
        else if (di->item_kind == ITEM_METAL) res_field = &player->res_metal;
        else if (di->item_kind == ITEM_STONE) res_field = &player->res_stone;
        if (res_field) {
            int new_val = (int)*res_field + (int)di->quantity;
            if (new_val > 9999) new_val = 9999;
            *res_field = (uint16_t)new_val;
            di->active = false;
            char resp[128];
            snprintf(resp, sizeof(resp),
                "{\"type\":\"message_ack\",\"status\":\"item_picked_up\",\"slot\":-1}");
            ws_send_text(client->fd, resp);
            log_info("🪵  Player %u picked up %u %s (drop id %u) into resource pool",
                     player->player_id, (unsigned)di->quantity,
                     di->item_kind == ITEM_WOOD  ? "wood"  :
                     di->item_kind == ITEM_FIBER ? "fiber" :
                     di->item_kind == ITEM_METAL ? "metal" : "stone",
                     item_id);
            return;
        }
    }

    int free_slot = -1;
    /* First: try to stack into an existing slot with the same item */
    for (int i = 0; i < INVENTORY_SLOTS; i++) {
        if (player->inventory.slots[i].item == (ItemKind)di->item_kind &&
            player->inventory.slots[i].quantity > 0 &&
            player->inventory.slots[i].quantity < 99) {
            free_slot = i; break;
        }
    }
    /* Fall back to an empty slot */
    if (free_slot < 0) {
        for (int i = 0; i < INVENTORY_SLOTS; i++) {
            if (player->inventory.slots[i].item == ITEM_NONE ||
                player->inventory.slots[i].quantity == 0) {
                free_slot = i; break;
            }
        }
    }
    if (free_slot < 0) {
        ws_send_text(client->fd, "{\"type\":\"error\",\"message\":\"inventory_full\"}");
        return;
    }
    if (player->inventory.slots[free_slot].item == (ItemKind)di->item_kind &&
        player->inventory.slots[free_slot].quantity > 0) {
        /* Stack onto existing */
        int new_qty = (int)player->inventory.slots[free_slot].quantity + (int)di->quantity;
        if (new_qty > 99) new_qty = 99;
        player->inventory.slots[free_slot].quantity = (uint8_t)new_qty;
    } else {
        player->inventory.slots[free_slot].item     = (ItemKind)di->item_kind;
        player->inventory.slots[free_slot].quantity = di->quantity;
    }
    di->active = false;
    char resp[128];
    snprintf(resp, sizeof(resp),
        "{\"type\":\"message_ack\",\"status\":\"item_picked_up\",\"slot\":%d}", free_slot);
    ws_send_text(client->fd, resp);
    log_info("📦  Player %u picked up drop id %u (item %u) into slot %d",
             player->player_id, item_id, (unsigned)di->item_kind, free_slot);
}



// ── Grapple hook handlers ─────────────────────────────────────────────────────

/**
 * Squared distance from point (px, py) to segment (ax,ay)→(bx,by).
 * Optionally returns the closest point on the segment in (*cx, *cy).
 * Used for line-based grapple hit detection so the rope can snag targets
 * anywhere along its length, not just at the hook tip.
 */
static float grapple_seg_dist_sq(float px, float py,
                                  float ax, float ay,
                                  float bx, float by,
                                  float* cx, float* cy)
{
    float dx = bx - ax, dy = by - ay;
    float len2 = dx*dx + dy*dy;
    float t = (len2 > 0.0f) ? ((px-ax)*dx + (py-ay)*dy) / len2 : 0.0f;
    if (t < 0.0f) t = 0.0f;
    if (t > 1.0f) t = 1.0f;
    float nx = ax + t*dx, ny = ay + t*dy;
    if (cx) *cx = nx;
    if (cy) *cy = ny;
    float ex = px - nx, ey = py - ny;
    return ex*ex + ey*ey;
}

/** Fire the grapple hook from player_idx toward (target_x, target_y).
 *  charge: 0.0 (minimum range) … 1.0 (full range), clamped server-side. */
static void handle_fire_grapple(int player_idx, float target_x, float target_y,
                                 float charge, uint32_t now_ms)
{
    WebSocketPlayer* player = &players[player_idx];

    /* Must be holding a grapple hook in the active slot. */
    uint8_t aslot = player->inventory.active_slot;
    if (aslot >= INVENTORY_SLOTS ||
        player->inventory.slots[aslot].item != ITEM_GRAPPLE_HOOK ||
        player->inventory.slots[aslot].quantity == 0) {
        return;
    }

    GrappleHook* gh = &grapple_hooks[player_idx];

    /* Cooldown check — prevent rapid re-fire. */
    if (gh->active && (now_ms - gh->fire_time_ms) < GRAPPLE_COOLDOWN_MS) return;

    /* Cancel any existing hook first. */
    grapple_detach(player_idx);

    /* Clamp and scale charge to actual range. */
    if (charge < 0.0f) charge = 0.0f;
    if (charge > 1.0f) charge = 1.0f;
    float actual_range = GRAPPLE_MIN_RANGE + charge * (GRAPPLE_MAX_RANGE - GRAPPLE_MIN_RANGE);

    /* Compute normalised direction toward target. */
    float ox = player->x, oy = player->y;
    float dx = target_x - ox, dy = target_y - oy;
    float dist = sqrtf(dx * dx + dy * dy);
    if (dist < 1.0f) { dx = 1.0f; dy = 0.0f; dist = 1.0f; }
    float nx = dx / dist, ny = dy / dist;

    /* Spawn hook slightly ahead of the player so it starts outside the ship's
     * GRAPPLE_HIT_R_SHIP radius when fired from a deck.  origin_x/y stays at
     * the player position so max-range is measured from the fire point. */
#define GRAPPLE_SPAWN_OFFSET 30.0f   /* px forward along aim */

    gh->active       = true;
    gh->player_idx   = player_idx;
    gh->state        = GRAPPLE_FLYING;
    gh->hook_x       = ox + nx * GRAPPLE_SPAWN_OFFSET;
    gh->hook_y       = oy + ny * GRAPPLE_SPAWN_OFFSET;
    gh->vel_x        = nx * GRAPPLE_SPEED;
    gh->vel_y        = ny * GRAPPLE_SPEED;
    gh->origin_x     = ox;
    gh->origin_y     = oy;
    gh->target_type  = GRAPPLE_TARGET_NONE;
    gh->target_id    = 0;
    gh->fire_time_ms = now_ms;
    gh->max_range    = actual_range;

    log_info("🪝  Player %u fired grapple charge=%.2f range=%.0f toward (%.0f,%.0f)",
             player->player_id, charge, actual_range, target_x, target_y);
}

/** Detach the grapple hook for a given player index. */
static void handle_release_grapple(int player_idx)
{
    if (grapple_hooks[player_idx].active) {
        log_info("🪝  Player %u released grapple",
                 players[player_idx].player_id);
    }
    grapple_detach(player_idx);
}

static int ws_player_slot(const WebSocketPlayer* p) {
    if (!p) return -1;
    for (int i = 0; i < WS_MAX_CLIENTS; i++) {
        if (&players[i] == p) return i;
    }
    return -1;
}

/** True when aboard one ship but the grapple hook is attached to another. */
static bool ws_player_grappling_other_ship(int slot, const WebSocketPlayer* p) {
    if (!p || p->parent_ship_id == 0) return false;
    if (slot < 0 || slot >= WS_MAX_CLIENTS) return false;
    const GrappleHook* gh = &grapple_hooks[slot];
    if (!gh->active || gh->state != GRAPPLE_ATTACHED ||
        gh->target_type != GRAPPLE_TARGET_SHIP) {
        return false;
    }
    return p->parent_ship_id != (uint16_t)gh->target_id;
}

/** After a ship-target grapple pull, sync local coords and dismount if pulled off deck. */
static void grapple_sync_owner_boarding_state(int owner_slot, const SimpleShip* target_ship) {
    WebSocketPlayer* owner = &players[owner_slot];
    if (owner->parent_ship_id == 0 || !target_ship) return;

    SimpleShip* cur = find_ship(owner->parent_ship_id);
    if (!cur) return;

    float lx, ly;
    ship_world_to_local(cur, owner->x, owner->y, &lx, &ly);
    owner->local_x = lx;
    owner->local_y = ly;

    if (global_sim && owner->sim_entity_id != 0) {
        struct Player* sp = sim_get_player(global_sim, owner->sim_entity_id);
        if (sp) {
            sp->relative_pos.x = Q16_FROM_FLOAT(CLIENT_TO_SERVER(lx));
            sp->relative_pos.y = Q16_FROM_FLOAT(CLIENT_TO_SERVER(ly));
            sp->ship_id = cur->ship_id;
        }
    }

    if (owner->parent_ship_id != target_ship->ship_id &&
        is_outside_deck(cur->ship_id, lx, ly)) {
        /* Exit at the reeled world position (hull edge), not ship_local_to_world(0,0). */
        float exit_wx = owner->x;
        float exit_wy = owner->y;
        dismount_player_from_ship(owner, "grapple_pull_off_deck");
        owner->x = exit_wx;
        owner->y = exit_wy;
        if (global_sim && owner->sim_entity_id != 0) {
            struct Player* sp = sim_get_player(global_sim, owner->sim_entity_id);
            if (sp) {
                sp->position.x = Q16_FROM_FLOAT(CLIENT_TO_SERVER(exit_wx));
                sp->position.y = Q16_FROM_FLOAT(CLIENT_TO_SERVER(exit_wy));
            }
        }
    }
}

/** After grapple reel/constraint moves the owner in world space, sync the sim entity
 * and invalidate stale client-reported positions so the next movement tick does not
 * copy an old sim position back over the reel progress. */
static void grapple_sync_owner_sim_position(WebSocketPlayer* owner) {
    if (!owner) return;
    if (global_sim && owner->sim_entity_id != 0) {
        struct Player* sp = sim_get_player(global_sim, owner->sim_entity_id);
        if (sp) {
            sp->position.x = Q16_FROM_FLOAT(CLIENT_TO_SERVER(owner->x));
            sp->position.y = Q16_FROM_FLOAT(CLIENT_TO_SERVER(owner->y));
            sp->velocity.x = 0;
            sp->velocity.y = 0;
        }
    }
    /* Drop any client position reported before/during the reel step — adopting it
     * on the next tick would yank the player back to their pre-reel location. */
    owner->client_pos_ms = 0;
}

/** After entity-target rope constraint moves a grappled NPC, sync local coords. */
static void grapple_sync_target_world_npc(WorldNpc* npc) {
    if (!npc) return;
    if (npc->ship_id != 0) {
        SimpleShip* ship = find_ship(npc->ship_id);
        if (ship)
            ship_world_to_local(ship, npc->x, npc->y, &npc->local_x, &npc->local_y);
    } else {
        npc->local_x = npc->x;
        npc->local_y = npc->y;
    }
    npc->target_local_x = npc->local_x;
    npc->target_local_y = npc->local_y;
    npc->velocity_x = 0.0f;
    npc->velocity_y = 0.0f;
}

/** After entity-target rope constraint moves a grappled player, sync sim + ship-local coords. */
static void grapple_sync_target_ws_player(WebSocketPlayer* tgt) {
    if (!tgt) return;
    if (tgt->parent_ship_id != 0) {
        SimpleShip* cur = find_ship(tgt->parent_ship_id);
        if (cur)
            ship_world_to_local(cur, tgt->x, tgt->y, &tgt->local_x, &tgt->local_y);
    }
    if (global_sim && tgt->sim_entity_id != 0) {
        struct Player* sp = sim_get_player(global_sim, tgt->sim_entity_id);
        if (sp) {
            sp->position.x = Q16_FROM_FLOAT(CLIENT_TO_SERVER(tgt->x));
            sp->position.y = Q16_FROM_FLOAT(CLIENT_TO_SERVER(tgt->y));
            if (tgt->parent_ship_id != 0) {
                sp->relative_pos.x = Q16_FROM_FLOAT(CLIENT_TO_SERVER(tgt->local_x));
                sp->relative_pos.y = Q16_FROM_FLOAT(CLIENT_TO_SERVER(tgt->local_y));
            }
            sp->velocity.x = 0;
            sp->velocity.y = 0;
        }
    }
    tgt->client_pos_ms = 0;
}

/**
 * Hard rope constraint for player/NPC grapple targets.
 * Target cannot drag the grappler — only the target is pulled back to rope_length.
 * Entity grapples never auto-detach on proximity; release is manual only.
 */
static void grapple_apply_entity_rope(GrappleHook* gh, WebSocketPlayer* owner,
                                      float* tgt_x, float* tgt_y) {
    float tdx   = owner->x - *tgt_x;
    float tdy   = owner->y - *tgt_y;
    float tdist = sqrtf(tdx * tdx + tdy * tdy);
    if (tdist < 0.5f) {
        gh->hook_x = *tgt_x;
        gh->hook_y = *tgt_y;
        return;
    }

    if (!gh->reel_out && tdist > gh->rope_length) {
        float over = tdist - gh->rope_length;
        float nx = tdx / tdist;
        float ny = tdy / tdist;
        *tgt_x += nx * over;
        *tgt_y += ny * over;
        tdist = gh->rope_length;
    }

    gh->hook_x = *tgt_x;
    gh->hook_y = *tgt_y;
}

/** Per-tick grapple physics.  Called from the main server tick with dt seconds. */
static void update_grapple_hooks(float dt, uint32_t now_ms)
{
    for (int si = 0; si < WS_MAX_CLIENTS; si++) {
        GrappleHook* gh = &grapple_hooks[si];
        if (!gh->active) continue;

        WebSocketPlayer* owner = &players[si];
        if (!owner->active) { grapple_detach(si); continue; }

        /* Safety timeout — only for FLYING hooks; attached hooks persist until
         * explicitly released, reeled past max, or the target disappears. */
        if (gh->state == GRAPPLE_FLYING &&
            now_ms - gh->fire_time_ms > GRAPPLE_TIMEOUT_MS) {
            grapple_detach(si);
            continue;
        }

        if (gh->state == GRAPPLE_FLYING) {
            /* Advance hook position. */
            gh->hook_x += gh->vel_x * dt;
            gh->hook_y += gh->vel_y * dt;

            /* Out-of-range check (uses per-shot charge-scaled range). */
            float rdx = gh->hook_x - gh->origin_x;
            float rdy = gh->hook_y - gh->origin_y;
            if (rdx * rdx + rdy * rdy > gh->max_range * gh->max_range) {
                grapple_detach(si);
                continue;
            }

            /* ── Hit detection ──────────────────────────────────────────────── */
            bool hit = false;

            /* Dropped items — tip AND rope-line check so flotsam can be snagged
             * anywhere along the rope's travel path, not just at the hook tip. */
            for (int di = 0; di < (int)MAX_DROPPED_ITEMS && !hit; di++) {
                if (!dropped_items[di].active) continue;
                float _iwx, _iwy;
                dropped_item_world_pos(&dropped_items[di], &_iwx, &_iwy);
                float ddx = gh->hook_x - _iwx;
                float ddy = gh->hook_y - _iwy;
                bool _tip_item = (ddx*ddx + ddy*ddy <= GRAPPLE_HIT_R_ITEM * GRAPPLE_HIT_R_ITEM);
                bool _line_item = false;
                if (!_tip_item) {
                    float _dsq = grapple_seg_dist_sq(
                        _iwx, _iwy,
                        gh->origin_x, gh->origin_y,
                        gh->hook_x, gh->hook_y, NULL, NULL);
                    _line_item = (_dsq <= GRAPPLE_HIT_R_ITEM * GRAPPLE_HIT_R_ITEM);
                }
                if (_tip_item || _line_item) {
                    gh->state       = GRAPPLE_ATTACHED;
                    gh->target_type = GRAPPLE_TARGET_DROPPED_ITEM;
                    gh->target_id   = (uint32_t)di;
                    gh->hook_x      = _iwx;
                    gh->hook_y      = _iwy;
                    hit = true;
                }
            }

            /* Ships — attach at actual hull edge, stored in ship-local space.
             * Guards:
             *  1. Skip the player's own ship (boarded via parent_ship_id OR scaffold).
             *  2. Require the hook to have travelled at least GRAPPLE_MIN_SHIP_TRAVEL px
             *     before any ship can be hit — prevents instant snap when spawning inside
             *     the 140 px hit radius on a deck. */
#define GRAPPLE_MIN_SHIP_TRAVEL 80.0f   /* px — must clear own hull before ship hits register */
            float _travel_sq = rdx * rdx + rdy * rdy;
            bool _can_hit_ship = (_travel_sq >= GRAPPLE_MIN_SHIP_TRAVEL * GRAPPLE_MIN_SHIP_TRAVEL);

            /* Resolve which ship ID the player is currently associated with (boarded or scaffold). */
            uint32_t _own_ship_id = (uint32_t)owner->parent_ship_id;
            if (_own_ship_id == 0 && owner->on_dock_id != 0) {
                for (int _dsi = 0; _dsi < (int)placed_structure_count; _dsi++) {
                    PlacedStructure* _ds = &placed_structures[_dsi];
                    if (_ds->active && _ds->id == owner->on_dock_id &&
                        _ds->type == STRUCT_SHIPYARD && _ds->scaffolded_ship_id != 0) {
                        _own_ship_id = _ds->scaffolded_ship_id;
                        break;
                    }
                }
            }

            for (int shp = 0; shp < ship_count && !hit && _can_hit_ship; shp++) {
                if (!ships[shp].active) continue;
                /* Skip own ship (boarded or scaffolded). */
                if (_own_ship_id != 0 && (uint32_t)ships[shp].ship_id == _own_ship_id) continue;

                struct Ship* _sim = find_sim_ship((uint32_t)ships[shp].ship_id);
                if (!_sim || _sim->hull_vertex_count < 3) continue;

                float _lhx, _lhy;
                bool _hull_hit = grapple_hook_on_hull(&ships[shp], _sim,
                                                      gh->hook_x, gh->hook_y,
                                                      &_lhx, &_lhy);
                if (!_hull_hit) {
                    _hull_hit = grapple_segment_hull_attach(&ships[shp], _sim,
                        gh->origin_x, gh->origin_y, gh->hook_x, gh->hook_y,
                        &_lhx, &_lhy);
                }
                if (_hull_hit) {
                    grapple_attach_to_ship(gh, &ships[shp], _lhx, _lhy, owner);
                    hit = true;
                }
            }

            /* Other players — tip AND rope-line check. */
            for (int pi = 0; pi < WS_MAX_CLIENTS && !hit; pi++) {
                if (pi == si) continue;
                if (!players[pi].active) continue;
                float pdx = gh->hook_x - players[pi].x;
                float pdy = gh->hook_y - players[pi].y;
                bool _tip_pl = (pdx*pdx + pdy*pdy <= GRAPPLE_HIT_R_ENTITY * GRAPPLE_HIT_R_ENTITY);
                if (!_tip_pl) {
                    float _pdsq = grapple_seg_dist_sq(
                        players[pi].x, players[pi].y,
                        gh->origin_x, gh->origin_y,
                        gh->hook_x, gh->hook_y, NULL, NULL);
                    _tip_pl = (_pdsq <= GRAPPLE_HIT_R_ENTITY * GRAPPLE_HIT_R_ENTITY);
                }
                if (_tip_pl) {
                    gh->state       = GRAPPLE_ATTACHED;
                    gh->target_type = GRAPPLE_TARGET_PLAYER;
                    gh->target_id   = players[pi].player_id;
                    gh->hook_x      = players[pi].x;
                    gh->hook_y      = players[pi].y;
                    hit = true;
                }
            }

            /* World NPCs — tip AND rope-line check.
             * Requires the same minimum travel as ships so that NPCs standing on
             * the player's own deck cannot be snagged the moment the hook spawns.
             * Also skip NPCs that belong to the player's own ship (no self-grapple). */
            for (int ni = 0; ni < world_npc_count && !hit && _can_hit_ship; ni++) {
                if (!world_npcs[ni].active) continue;
                /* Skip NPCs on the player's own ship. */
                if (_own_ship_id != 0 && world_npcs[ni].ship_id == _own_ship_id) continue;
                float ndx = gh->hook_x - world_npcs[ni].x;
                float ndy = gh->hook_y - world_npcs[ni].y;
                bool _tip_npc = (ndx*ndx + ndy*ndy <= GRAPPLE_HIT_R_ENTITY * GRAPPLE_HIT_R_ENTITY);
                if (!_tip_npc) {
                    float _ndsq = grapple_seg_dist_sq(
                        world_npcs[ni].x, world_npcs[ni].y,
                        gh->origin_x, gh->origin_y,
                        gh->hook_x, gh->hook_y, NULL, NULL);
                    _tip_npc = (_ndsq <= GRAPPLE_HIT_R_ENTITY * GRAPPLE_HIT_R_ENTITY);
                }
                if (_tip_npc) {
                    gh->state       = GRAPPLE_ATTACHED;
                    gh->target_type = GRAPPLE_TARGET_NPC;
                    gh->target_id   = (uint32_t)ni;
                    gh->hook_x      = world_npcs[ni].x;
                    gh->hook_y      = world_npcs[ni].y;
                    hit = true;
                }
            }

            /* Wreck structures (chest_ruin flotsam) — tip AND rope-line check.
             * Requires minimum travel so a wreck sitting next to the player's
             * ship does not immediately swallow the hook the moment it spawns. */
            for (int wi = 0; wi < (int)placed_structure_count && !hit && _can_hit_ship; wi++) {
                PlacedStructure* wr = &placed_structures[wi];
                if (!wr->active || wr->type != STRUCT_WRECK) continue;
                float wdx = gh->hook_x - wr->x;
                float wdy = gh->hook_y - wr->y;
                bool _tip_wr = (wdx*wdx + wdy*wdy <= GRAPPLE_HIT_R_WRECK * GRAPPLE_HIT_R_WRECK);
                if (!_tip_wr) {
                    float _wdsq = grapple_seg_dist_sq(
                        wr->x, wr->y,
                        gh->origin_x, gh->origin_y,
                        gh->hook_x, gh->hook_y, NULL, NULL);
                    _tip_wr = (_wdsq <= GRAPPLE_HIT_R_WRECK * GRAPPLE_HIT_R_WRECK);
                }
                if (_tip_wr) {
                    gh->state       = GRAPPLE_ATTACHED;
                    gh->target_type = GRAPPLE_TARGET_WRECK;
                    gh->target_id   = (uint32_t)wi;
                    gh->hook_x      = wr->x;
                    gh->hook_y      = wr->y;
                    hit = true;
                }
            }

        } else if (gh->state == GRAPPLE_ATTACHED) {
            /* ── Rope-length init on first attached tick ─────────────────────── */
            if (gh->rope_length <= 0.0f) {
                float _irx = gh->hook_x - owner->x;
                float _iry = gh->hook_y - owner->y;
                gh->rope_length = sqrtf(_irx * _irx + _iry * _iry);
                if (gh->rope_length < GRAPPLE_ROPE_MIN) gh->rope_length = GRAPPLE_ROPE_MIN;
                gh->fire_time_ms = now_ms; /* reset timeout clock from attachment moment */
            }

            /* ── Reel out (non-ship targets: also shortens rope_length for reel-in) ── */
            if (gh->reel_out) {
                gh->rope_length += GRAPPLE_REEL_RATE * dt;
                if (gh->rope_length >= gh->max_range) {
                    log_info("🪝  Player %u rope paid out to max — grapple snapped",
                             players[si].player_id);
                    grapple_detach(si);
                    continue;
                }
            }
            /* Non-ship reel-in: shorten rope_length so constraint does the pull. */
            if (gh->reel_in && gh->target_type != GRAPPLE_TARGET_SHIP) {
                if (player_grapple_encumbered(si, owner)) {
                    gh->reel_in = false;
                } else {
                    gh->rope_length -= GRAPPLE_REEL_RATE * dt;
                    if (gh->rope_length < GRAPPLE_ROPE_MIN) gh->rope_length = GRAPPLE_ROPE_MIN;
                }
            }

            /* Entity grapples: stop reel-in when overencumbered (rope stays attached). */
            if (grapple_target_is_entity(gh->target_type) &&
                player_grapple_encumbered(si, owner)) {
                gh->reel_in = false;
            }

            /* ── Pull logic ─────────────────────────────────────────────────── */

            switch (gh->target_type) {

            case GRAPPLE_TARGET_DROPPED_ITEM: {
                int di = (int)gh->target_id;
                if (di < 0 || di >= (int)MAX_DROPPED_ITEMS || !dropped_items[di].active) {
                    grapple_detach(si); break;
                }
                float _iwx, _iwy;
                dropped_item_world_pos(&dropped_items[di], &_iwx, &_iwy);
                /* Pull item toward player only when it is farther than the current rope. */
                float idx = owner->x - _iwx;
                float idy = owner->y - _iwy;
                float idist = sqrtf(idx * idx + idy * idy);
                if (idist < GRAPPLE_DETACH_DIST) {
                    /* Auto pick-up: attempt to give item to player. */
                    bool stacked = false;
                    for (int s = 0; s < INVENTORY_SLOTS; s++) {
                        InventorySlot* isl = &owner->inventory.slots[s];
                        if (isl->item == (ItemKind)dropped_items[di].item_kind &&
                            isl->quantity > 0 && isl->quantity < 99) {
                            int add = (int)dropped_items[di].quantity;
                            if (isl->quantity + add > 99) add = 99 - isl->quantity;
                            isl->quantity += (uint8_t)add;
                            dropped_items[di].quantity -= (uint8_t)add;
                            stacked = true;
                        }
                    }
                    if (!stacked || dropped_items[di].quantity == 0) {
                        if (dropped_items[di].quantity > 0) {
                            for (int s = 0; s < INVENTORY_SLOTS; s++) {
                                InventorySlot* isl = &owner->inventory.slots[s];
                                if (isl->item == ITEM_NONE || isl->quantity == 0) {
                                    isl->item     = (ItemKind)dropped_items[di].item_kind;
                                    isl->quantity = dropped_items[di].quantity;
                                    dropped_items[di].quantity = 0;
                                    break;
                                }
                            }
                        }
                        dropped_items[di].active = false;
                    }
                    grapple_detach(si);
                } else if (idist > gh->rope_length) {
                    float step = GRAPPLE_PULL_SPEED * dt / idist;
                    dropped_item_set_world_pos(&dropped_items[di],
                        _iwx + idx * step, _iwy + idy * step);
                    dropped_item_world_pos(&dropped_items[di], &gh->hook_x, &gh->hook_y);
                }
                break;
            }

            case GRAPPLE_TARGET_SHIP: {
                SimpleShip* tship = find_ship((uint16_t)gh->target_id);
                if (!tship || !tship->active) { grapple_detach(si); break; }

                /* Hook locked to local-space offset, rotated with ship. */
                float _hcosR = cosf(tship->rotation);
                float _hsinR = sinf(tship->rotation);
                gh->hook_x = tship->x + gh->vel_x * _hcosR - gh->vel_y * _hsinR;
                gh->hook_y = tship->y + gh->vel_x * _hsinR + gh->vel_y * _hcosR;

                /* Vector from hook to player. */
                float tdx   = owner->x - gh->hook_x;
                float tdy   = owner->y - gh->hook_y;
                float tdist = sqrtf(tdx * tdx + tdy * tdy);
                if (tdist < 0.5f) break;

                float nx = tdx / tdist;
                float ny = tdy / tdist;

                if (gh->reel_in) {
                    /* ── Mode A: LMB held — actively pull player toward ship ────── */
                    float step   = GRAPPLE_REEL_PULL * dt;
                    float newdist = tdist - step;
                    if (newdist < 0.0f) newdist = 0.0f;
                    step = tdist - newdist;  /* actual movement this tick */
                    if (step > 0.0f) {
                        owner->x -= nx * step;
                        owner->y -= ny * step;
                        gh->rope_length = newdist;  /* track where the rope currently sits */
                        grapple_sync_owner_sim_position(owner);
                    }
                    /* Reel all the way to the hook. Boarding stops reel-in on the client;
                     * do NOT clamp at GRAPPLE_ROPE_MIN or the player stalls short of the hull. */
                } else if (!gh->reel_out) {
                    /* ── Mode B: idle — instant rope constraint (hard stop at rope_length) ── */
                    if (tdist > gh->rope_length) {
                        float over = tdist - gh->rope_length;
                        owner->x -= nx * over;
                        owner->y -= ny * over;
                        grapple_sync_owner_sim_position(owner);
                    }
                }
                /* Keep local anchor in sync; dismount when reel pulls off the current deck. */
                if (owner->parent_ship_id != 0) {
                    grapple_sync_owner_boarding_state(si, tship);
                }
                /* ── Mode C: RMB held — rope extends freely, no constraint ──────── */
                /* (rope_length is already being extended by reel_out section above) */
                break;
            }

            case GRAPPLE_TARGET_PLAYER: {
                WebSocketPlayer* tgt = find_player(gh->target_id);
                if (!tgt || !tgt->active) { grapple_detach(si); break; }

                grapple_apply_entity_rope(gh, owner, &tgt->x, &tgt->y);
                grapple_sync_target_ws_player(tgt);
                break;
            }

            case GRAPPLE_TARGET_NPC: {
                int ni = (int)gh->target_id;
                if (ni < 0 || ni >= world_npc_count || !world_npcs[ni].active) {
                    grapple_detach(si); break;
                }
                grapple_apply_entity_rope(gh, owner, &world_npcs[ni].x, &world_npcs[ni].y);
                grapple_sync_target_world_npc(&world_npcs[ni]);
                break;
            }

            case GRAPPLE_TARGET_WRECK: {
                int wi = (int)gh->target_id;
                if (wi < 0 || wi >= (int)placed_structure_count ||
                    !placed_structures[wi].active ||
                    placed_structures[wi].type != STRUCT_WRECK) {
                    grapple_detach(si); break;
                }
                PlacedStructure* twr = &placed_structures[wi];
                float tdx   = owner->x - twr->x;
                float tdy   = owner->y - twr->y;
                float tdist = sqrtf(tdx * tdx + tdy * tdy);
                if (tdist < GRAPPLE_DETACH_DIST) {
                    /* Auto-salvage: a wreck can hold THREE kinds of loot. Grant all:
                     *   1. Resource cache  (chest_ruin) → res_grant into resource pool
                     *   2. Blueprints      (ship-wreck) → schematic_add into schematic store
                     *   3. Item loot       (ship-wreck) → craft_grant into item inventory
                     * The previous version only handled the resource cache, so blueprint/
                     * item wrecks (normal sea wrecks) gave the player nothing. */

                    /* 1. Resource cache (chest-ruin wrecks).
                     * Capture quantities, clear the wreck fields BEFORE granting so that
                     * if the wreck survives (inventory full for items/blueprints) a second
                     * grapple approach cannot re-grant the same resources (duplication). */
                    int _lw = (int)twr->chest_wood,  _lf = (int)twr->chest_fiber;
                    int _lm = (int)twr->chest_metal, _ls = (int)twr->chest_stone;
                    twr->chest_wood  = 0;
                    twr->chest_fiber = 0;
                    twr->chest_metal = 0;
                    twr->chest_stone = 0;
                    if (_lw > 0) res_grant(owner, RES_WOOD_ID,  _lw);
                    if (_lf > 0) res_grant(owner, RES_FIBER_ID, _lf);
                    if (_lm > 0) res_grant(owner, RES_METAL_ID, _lm);
                    if (_ls > 0) res_grant(owner, RES_STONE_ID, _ls);

                    /* 2. Blueprints → persistent schematic inventory. */
                    int _bp_granted = 0;
                    for (int _bi = 0; _bi < 6; _bi++) {
                        if (twr->wreck_bp_items[_bi] == 0) continue;
                        if (schematic_add(owner, (ItemKind)twr->wreck_bp_items[_bi],
                                          twr->wreck_bp_crafts[_bi],
                                          &twr->wreck_bp_quality[_bi])) {
                            twr->wreck_bp_items[_bi]  = 0;
                            twr->wreck_bp_crafts[_bi] = 0;
                            if (twr->wreck_bp_count > 0) twr->wreck_bp_count--;
                            _bp_granted++;
                        }
                    }

                    /* 3. Item loot → item inventory. */
                    int _items_granted = 0;
                    for (int _li = 0; _li < 6; _li++) {
                        if (twr->wreck_items[_li] == 0 || twr->wreck_qtys[_li] == 0) continue;
                        if (craft_grant(owner, (ItemKind)twr->wreck_items[_li],
                                        (int)twr->wreck_qtys[_li])) {
                            twr->wreck_items[_li] = 0;
                            twr->wreck_qtys[_li]  = 0;
                            if (twr->wreck_loot_count > 0) twr->wreck_loot_count--;
                            _items_granted++;
                        }
                    }

                    /* Notify the salvaging player what resources they received
                     * (item/blueprint pickups surface via their own grant paths). */
                    {
                        char _loot[256];
                        snprintf(_loot, sizeof(_loot),
                            "{\"type\":\"wreck_loot\",\"playerId\":%u"
                            ",\"x\":%.1f,\"y\":%.1f"
                            ",\"wood\":%d,\"fiber\":%d,\"metal\":%d,\"stone\":%d"
                            ",\"items\":%d,\"blueprints\":%d}",
                            owner->player_id, owner->x, owner->y,
                            _lw, _lf, _lm, _ls, _items_granted, _bp_granted);
                        websocket_server_broadcast(_loot);
                    }

                    /* If the inventory was full and loot remains, leave the wreck in
                     * place so the player can free space and salvage the rest by hand. */
                    bool _fully_looted = (twr->wreck_bp_count == 0 && twr->wreck_loot_count == 0);
                    if (_fully_looted) {
                        uint32_t wreck_id = twr->id;
                        twr->active = false;
                        char wbcast[96];
                        snprintf(wbcast, sizeof(wbcast),
                                 "{\"type\":\"wreck_removed\",\"id\":%u}", (unsigned)wreck_id);
                        websocket_server_broadcast(wbcast);
                    } else {
                        char wbcast[128];
                        snprintf(wbcast, sizeof(wbcast),
                                 "{\"type\":\"wreck_updated\",\"id\":%u,\"loot_count\":%u,\"bp_count\":%u}",
                                 (unsigned)twr->id,
                                 (unsigned)twr->wreck_loot_count, (unsigned)twr->wreck_bp_count);
                        websocket_server_broadcast(wbcast);
                    }
                    grapple_detach(si);
                    break;
                }
                /* Pull wreck toward player at a constant speed — no rope_length
                 * gate here because for wrecks the wreck moves, not the player. */
                {
                    float step = GRAPPLE_PULL_SPEED * dt / tdist;
                    if (step > 1.0f) step = 1.0f; /* clamp: never overshoot */
                    twr->x += tdx * step;
                    twr->y += tdy * step;
                }
                gh->hook_x = twr->x;
                gh->hook_y = twr->y;
                /* Shrink rope so the client rope visual follows the closing distance. */
                gh->rope_length = tdist;
                /* Broadcast the new wreck position so all clients see it move. */
                {
                    char _wu[128];
                    snprintf(_wu, sizeof(_wu),
                        "{\"type\":\"wreck_update\",\"id\":%u,\"x\":%.1f,\"y\":%.1f}",
                        (unsigned)twr->id, twr->x, twr->y);
                    websocket_server_broadcast(_wu);
                }
                break;
            }

            default:
                grapple_detach(si);
                break;
            }
        }
    }
}

